import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const LANGUAGES = [
  "English", "Spanish", "French", "German", "Chinese (Simplified)", 
  "Japanese", "Korean", "Portuguese", "Italian", "Russian", "Arabic", "Hindi"
];

const App: React.FC = () => {
  const [sourceHtml, setSourceHtml] = useState<string>('<!-- Paste your HTML here -->\n<div class="hero">\n  <h1>Welcome to our website</h1>\n  <p>Discover the beauty of modern web localization.</p>\n  <button title="Click to learn more">Get Started</button>\n</div>');
  const [translatedHtml, setTranslatedHtml] = useState<string>('');
  const [targetLang, setTargetLang] = useState<string>('Spanish');
  const [isTranslating, setIsTranslating] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const translate = async () => {
    if (!sourceHtml.trim()) return;

    setIsTranslating(true);
    setError(null);
    setTranslatedHtml('');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: `Translate the following HTML code to ${targetLang}. 

        CRITICAL RULES:
        1. Keep all HTML tags, attributes (class, id, style, data-*), and overall structure EXACTLY the same.
        2. Translate only the human-readable text content inside tags.
        3. Translate relevant attributes like 'title', 'alt', 'placeholder', and 'aria-label'.
        4. Do NOT translate technical strings, URLs, or variable placeholders (e.g. {{name}}).
        5. Return ONLY the translated HTML code, no markdown code blocks.

        HTML TO TRANSLATE:
        ${sourceHtml}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          setTranslatedHtml(fullText);
        }
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during translation.');
    } finally {
      setIsTranslating(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('Copied to clipboard!');
  };

  const downloadHtml = () => {
    const blob = new Blob([translatedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `translated_${targetLang.toLowerCase()}.html`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col gap-6 max-w-7xl mx-auto">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 glass p-6 rounded-2xl shadow-2xl">
