const LANGUAGES = [
  "English", "Spanish", "French", "German", "Chinese (Simplified)", 
  "Japanese", "Korean", "Portuguese", "Italian", "Russian", "Arabic", "Hindi"
];

type ErrorType = 'AUTH' | 'RATE_LIMIT' | 'SAFETY' | 'INVALID_INPUT' | 'SERVER' | 'UNKNOWN';

interface AppError {
  type: ErrorType;
  message: string;
  canRetry: boolean;
}

const App: React.FC = () => {
  const [sourceHtml, setSourceHtml] = useState<string>('<!-- Paste your HTML here -->\n<div class="hero">\n  <h1>Welcome to our website</h1>\n  <p>Discover the beauty of modern web localization.</p>\n  <button title="Click to learn more">Get Started</button>\n</div>');
  const [translatedHtml, setTranslatedHtml] = useState<string>('');
  const [targetLang, setTargetLang] = useState<string>('Spanish');
  const [isTranslating, setIsTranslating] = useState<boolean>(false);
  const [error, setError] = useState<AppError | null>(null);
  const [eta, setEta] = useState<number | null>(null);
  const [showNotification, setShowNotification] = useState<boolean>(false);
  const [retryTimer, setRetryTimer] = useState<number>(0);

  // Helper to strip markdown formatting if the model adds it
  const cleanHtmlOutput = (text: string) => {
    return text.replace(/^```html\n?/, '').replace(/\n?```$/, '').trim();
  };

  const calculateEta = (text: string) => {
    const estimatedTokens = text.length / 4;
    return Math.max(3, Math.ceil(estimatedTokens / 75));
  };

  const diagnoseError = (err: any): AppError => {
    const msg = err?.message?.toLowerCase() || '';
    if (msg.includes('api key') || msg.includes('401')) {
      return { type: 'AUTH', message: 'Invalid API Key. Please check your environment configuration.', canRetry: false };
    }
    if (msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) {
      return { type: 'RATE_LIMIT', message: 'Rate limit exceeded. The API is busy.', canRetry: true };
    }
    if (msg.includes('safety') || msg.includes('blocked')) {
      return { type: 'SAFETY', message: 'The content was flagged by safety filters and cannot be translated.', canRetry: false };
    }
    if (msg.includes('500') || msg.includes('503') || msg.includes('server')) {
      return { type: 'SERVER', message: 'Gemini server is currently experiencing issues.', canRetry: true };
    }
    return { type: 'UNKNOWN', message: err.message || 'An unexpected error occurred.', canRetry: true };
  };

  const translate = async () => {
    if (!sourceHtml.trim()) return;

    // Basic pre-flight check
    if (!sourceHtml.includes('<') || !sourceHtml.includes('>')) {
      setError({ 
        type: 'INVALID_INPUT', 
        message: 'The input does not appear to be valid HTML. Please ensure you include tags.', 
        canRetry: true 
      });
      return;
    }

    setIsTranslating(true);
    setError(null);
    setTranslatedHtml('');
    setShowNotification(false);

    const estimatedSeconds = calculateEta(sourceHtml);
    setEta(estimatedSeconds);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: `You are a professional localization engine. Translate the provided HTML to ${targetLang}.

        STRICT OPERATIONAL RULES:
        1. IDENTICAL STRUCTURE: Every tag, attribute name, class, ID, and comment must be identical to the source. Do not add, remove, or "optimize" any part of the HTML structure.
        2. NO MARKDOWN: Output only raw HTML. Do not wrap in triple backticks.
        3. LOCAL ADAPTATION: Adapt the text content to make sense for a native speaker in the target locale. Use cultural idioms where appropriate instead of literal translations.
        4. ATTRIBUTE TARGETS: Translate 'title', 'alt', 'placeholder', 'aria-label', and 'value' (for buttons/inputs). 
        5. PROTECTED DATA: Do not translate URLs, email addresses, technical IDs, or strings inside brackets like {{user_name}}.

        HTML SOURCE:
        ${sourceHtml}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          setTranslatedHtml(cleanHtmlOutput(fullText));
          setEta(prev => (prev && prev > 1 ? prev - 0.1 : 1));
        }
      }

      setShowNotification(true);
      setTimeout(() => setShowNotification(false), 5000);

    } catch (err: any) {
      console.error('Translation Error:', err);
      setError(diagnoseError(err));
    } finally {
      setIsTranslating(false);
      setEta(null);
    }
  };

