        if (prev <= 1) {
          clearInterval(interval);
          translate();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    triggerNotification('Copied to clipboard');
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col gap-6 max-w-7xl mx-auto relative overflow-x-hidden">
      {/* Toast Notification */}
      <div className={`fixed top-6 right-6 z-[60] transition-all duration-500 transform ${showNotification ? 'translate-x-0 opacity-100' : 'translate-x-full opacity-0'}`}>
        <div className="bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 border border-emerald-400/30">
          <div className="bg-white/20 p-1.5 rounded-full">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7" /></svg>
          </div>
          <div>
            <p className="font-bold text-sm">Action Confirmed</p>
            <p className="text-xs text-emerald-100">{showNotification}</p>
          </div>
        </div>
      </div>

      {/* Vault Overlay */}
      {showVault && (
        <div className="fixed inset-0 z-[70] flex items-center justify-end">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowVault(false)}></div>
          <div className="relative w-full max-w-md h-full bg-slate-900 border-l border-slate-800 shadow-2xl p-8 overflow-y-auto animate-slide-in">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <svg className="w-5 h-5 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>
                Project Vault
              </h2>
              <button onClick={() => setShowVault(false)} className="text-slate-500 hover:text-white transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-4">
              {savedProjects.length === 0 ? (
                <div className="text-center py-20 opacity-30 italic text-sm">
                  Your vault is currently empty
                </div>
              ) : (
                savedProjects.map(p => (
                  <div 
                    key={p.id} 
                    onClick={() => loadProject(p)}
                    className="bg-slate-800/50 border border-slate-700 p-4 rounded-xl cursor-pointer hover:bg-slate-800 hover:border-indigo-500/50 transition-all group"
                  >
                    <div className="flex justify-between items-start mb-2">
                      <span className="text-[10px] uppercase font-black text-indigo-400 tracking-widest">{new Date(p.timestamp).toLocaleString()}</span>
                      <button 
                        onClick={(e) => deleteProject(p.id, e)}
                        className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-400 transition-all"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    </div>
                    <p className="text-xs text-slate-300 font-medium mb-1 truncate">Target: {p.targetLang}</p>
                    <div className="text-[9px] text-slate-500 font-mono truncate">{p.source.substring(0, 60)}...</div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 glass p-6 rounded-2xl shadow-2xl relative overflow-hidden group">
        <div className={`absolute top-0 left-0 w-1.5 h-full transition-colors duration-500 ${isTranslating || isDetecting ? 'bg-cyan-400 animate-pulse' : 'bg-indigo-500'}`}></div>
        <div>
          <h1 className="text-3xl font-bold bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent tracking-tight">
            Translatify <span className="text-slate-500 font-light italic">Pro</span>
          </h1>
          <p className="text-slate-400 text-sm mt-1 font-medium flex items-center gap-2">
            <span className={`w-2 h-2 rounded-full ${isTranslating || isDetecting ? 'bg-cyan-400 animate-pulse' : 'bg-slate-600'}`}></span>
            {isDetecting ? 'Analyzing Source Language...' : isTranslating ? 'Background Localization Active' : 'Ready for Transmission'}
