          <button
            onClick={translate}
            disabled={isTranslating || isDetecting || retryTimer > 0}
            className={`mt-auto px-10 py-2.5 rounded-xl font-bold transition-all transform hover:scale-[1.02] active:scale-95 flex items-center gap-3 border ${
              isTranslating || isDetecting || retryTimer > 0
                ? 'bg-slate-800 border-slate-700 text-slate-500 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-500 text-white border-indigo-400 shadow-lg shadow-indigo-500/30'
