              </>
            ) : isTranslating ? (
              <>
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ETA: {Math.ceil(eta || 0)}s
              </>
            ) : retryTimer > 0 ? (
              `Retrying in ${retryTimer}s...`
            ) : (
              'Start Localization'
            )}
          </button>
        </div>
      </header>

      {error && (
        <div className={`border p-5 rounded-2xl flex items-start gap-4 animate-headshake ${
          error.canRetry ? 'bg-amber-500/10 border-amber-500/50' : 'bg-red-500/10 border-red-500/50'
        }`}>
          <div className={`p-2 rounded-lg ${error.canRetry ? 'bg-amber-500/20 text-amber-400' : 'bg-red-500/20 text-red-400'}`}>
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
          </div>
          <div className="flex-grow">
            <h3 className={`font-bold text-sm mb-1 ${error.canRetry ? 'text-amber-200' : 'text-red-200'}`}>
              {error.type === 'RATE_LIMIT' ? 'Server Busy' : error.type === 'AUTH' ? 'Configuration Required' : error.type === 'INVALID_INPUT' ? 'Input Validation Warning' : 'Translation Error'}
            </h3>
            <p className="text-sm opacity-80 mb-3">{error.message}</p>
            {error.canRetry && (
              <button 
                onClick={handleRetry}
                disabled={retryTimer > 0}
                className="text-xs font-bold uppercase tracking-widest px-4 py-2 bg-amber-500 text-amber-950 rounded-lg hover:bg-amber-400 transition-colors disabled:opacity-50"
              >
                {retryTimer > 0 ? `Preparing Retry (${retryTimer}s)` : 'Attempt Retry'}
              </button>
            )}
          </div>
        </div>
      )}

      {/* Editor Grid */}
      <main className="grid grid-cols-1 md:grid-cols-2 gap-6 flex-grow h-[60vh]">
        <div className="flex flex-col group">
          <div className="flex items-center justify-between mb-2 px-2 h-6">
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Master Source Buffer</span>
              {detectedLang && !isDetecting && (
                <span className="text-[10px] bg-indigo-500/20 text-indigo-400 px-2 py-0.5 rounded border border-indigo-500/30 font-bold animate-fade-in">
                  Detected: {detectedLang}
                </span>
              )}
            </div>
            <button 
              onClick={() => {setSourceHtml(''); setError(null); setDetectedLang(null);}}
              className="text-[10px] uppercase font-bold text-slate-600 hover:text-red-400 transition-colors"
            >
              Wipe Buffer
            </button>
          </div>
          <textarea
            value={sourceHtml}
            onChange={(e) => {
              setSourceHtml(e.target.value);
              if (detectedLang) setDetectedLang(null);
            }}
            className={`w-full h-full bg-slate-900 border border-slate-800 group-hover:border-slate-700 rounded-2xl p-6 code-font text-sm text-slate-300 focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/50 outline-none resize-none transition-all shadow-2xl ${isDetecting ? 'animate-pulse' : ''}`}
            placeholder="Paste raw HTML here..."
            spellCheck={false}
          />
