        <div className="flex flex-col group">
          <div className="flex items-center justify-between mb-2 px-2 h-6">
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Localized Live Stream</span>
            {translatedHtml && !isTranslating && (
              <button 
                onClick={() => copyToClipboard(translatedHtml)}
                className="text-[10px] text-indigo-400 hover:text-indigo-300 font-black uppercase tracking-widest transition-colors flex items-center gap-1.5"
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
                Copy Localized HTML
              </button>
            )}
          </div>
          <div className="relative w-full h-full">
            <textarea
              value={translatedHtml}
              readOnly
              placeholder={isDetecting ? "Identifying source patterns..." : isTranslating ? "Connecting to engine..." : "Awaiting transmission..."}
              className={`w-full h-full bg-slate-950 border rounded-2xl p-6 code-font text-sm outline-none resize-none transition-all shadow-2xl ${
                isTranslating || isDetecting ? 'border-cyan-500/30 text-cyan-100' : 'border-slate-800 text-emerald-400/90'
              }`}
              spellCheck={false}
            />
            {(isTranslating || isDetecting) && (
              <div className="absolute top-4 right-4 flex items-center gap-2 bg-cyan-500/10 px-4 py-2 rounded-xl border border-cyan-500/20 shadow-lg animate-fade-in">
                <div className="flex space-x-1.5">
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                  <div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce"></div>
                </div>
                <span className="text-[10px] text-cyan-400 font-black uppercase tracking-widest">{isDetecting ? 'Detecting' : 'Streaming'}</span>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Task Tracker */}
      <div className="flex items-center gap-4 py-4 opacity-60">
        <div className="flex-grow h-[2px] bg-slate-800 rounded-full overflow-hidden">
          {(isTranslating || isDetecting) && (
            <div className="h-full bg-gradient-to-r from-indigo-500 via-cyan-400 to-indigo-500 w-[60%] animate-[shimmer_2s_infinite_linear]" style={{ backgroundSize: '200% 100%' }}></div>
          )}
        </div>
      </div>

      <footer className="text-center text-slate-600 text-[10px] font-black uppercase tracking-[0.4em] py-4 border-t border-slate-900/50">
        Mirror Engine &bull; Zero structural modification &bull; Persistence Enabled
      </footer>

      <style>{`
        @keyframes shimmer {
          0% { background-position: 100% 0; }
          100% { background-position: -100% 0; }
        }
        @keyframes headshake {
          0% { transform: translateX(0); }
          6.5% { transform: translateX(-6px) rotateY(-9deg); }
          18.5% { transform: translateX(5px) rotateY(7deg); }
          31.5% { transform: translateX(-3px) rotateY(-5deg); }
          43.5% { transform: translateX(2px) rotateY(3deg); }
          50% { transform: translateX(0); }
        }
        @keyframes slideIn {
          from { transform: translateX(100%); }
          to { transform: translateX(0); }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(5px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-headshake { animation: headshake 1s ease-in-out; }
        .animate-slide-in { animation: slideIn 0.3s cubic-bezier(0.16, 1, 0.3, 1); }
        .animate-fade-in { animation: fadeIn 0.4s ease-out; }
      `}</style>
    </div>
  );
};

const rootElement = document.getElementById('root');
if (rootElement) {
  createRoot(rootElement).render(<App />);
