  }, [sourceHtml, selectedLangs]);

  const detectedImages = useMemo<ImageAsset[]>(() => {
    const images: ImageAsset[] = [];
    const parser = new DOMParser();
    const doc = parser.parseFromString(sourceHtml, 'text/html');
    const imgTags = doc.querySelectorAll('img');
    imgTags.forEach(img => {
      const src = img.getAttribute('src');
      const alt = img.getAttribute('alt') || '';
      if (src && (alt.length > 5 || img.closest('.hero, .carousel, .banner, header'))) {
        images.push({ url: src, alt, type: 'img', context: img.parentElement?.tagName.toLowerCase() || 'div' });
      }
    });
    const bgMatches = sourceHtml.match(/url\(['"]?(.*?)['"]?\)/g);
