      bgMatches.forEach(match => {
        const url = match.replace(/url\(['"]?(.*?)['"]?\)/, '$1');
        if (!images.find(i => i.url === url)) images.push({ url, alt: 'Background Asset', type: 'background', context: 'css-style' });
