    setJobs(prev => ({
      ...prev,
      [lang]: { lang, translatedHtml: '', status: 'translating', progress: 5, eta: initialEta }
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: `Translate the provided HTML from ${detected || 'its source language'} to ${lang}.
        RULES: 
        1. Keep DOM structure identical. 
        2. Do not translate URLs, emails, or {{vars}}. 
        3. Localize text naturally.

        HTML: ${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        fullText += chunk.text;
        const currentHtml = cleanHtmlOutput(fullText);
        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: currentHtml,
            progress: Math.min(98, prev[lang].progress + 2),
            eta: Math.max(1, prev[lang].eta - 0.2)
          }
        }));
      }

      setJobs(prev => ({
        ...prev,
        [lang]: { ...prev[lang], status: 'completed', progress: 100, eta: 0 }
      }));
