    <div className="min-h-screen p-4 md:p-8 flex flex-col gap-6 max-w-screen-2xl mx-auto relative overflow-x-hidden">
      {/* Toast */}
      <div className={`fixed top-6 right-6 z-[100] transition-all duration-500 transform ${showNotification ? 'translate-x-0 opacity-100' : 'translate-x-full opacity-0'}`}>
        <div className="bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 border border-emerald-400/30">
          <div className="bg-white/20 p-1.5 rounded-full"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7" /></svg></div>
          <p className="font-bold text-sm">{showNotification}</p>
        </div>
      </div>

      {/* Media Lab Overlay (Identical to previous implementation) */}
      {showMediaLab && (
        <div className="fixed inset-0 z-[80] flex items-center justify-end">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowMediaLab(false)}></div>
          <div className="relative w-full max-w-lg h-full bg-slate-900 border-l border-slate-800 shadow-2xl p-8 overflow-y-auto animate-slide-in">
             <div className="flex items-center justify-between mb-8">
              <h2 className="text-xl font-bold text-white flex items-center gap-3">
                <svg className="w-6 h-6 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                Media Intelligence Lab
              </h2>
              <button onClick={() => setShowMediaLab(false)} className="text-slate-500 hover:text-white transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
