                    </h3>
                    <p className="text-[10px] text-slate-500 uppercase tracking-tighter">
                      {job?.status === 'translating' ? `ETA: ${Math.ceil(job.eta)}s` : job?.status === 'completed' ? 'Fully Localized' : 'Ready'}
