                    </button>
                  )}
                </div>

                {job?.status === 'translating' && (
                  <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.5)] transition-all duration-500" style={{ width: `${job.progress}%` }}></div>
                  </div>
                )}

                <div className="flex-grow bg-slate-950/50 rounded-2xl p-4 border border-slate-800/50 overflow-y-auto max-h-[200px] text-[11px] code-font text-emerald-400/80 whitespace-pre-wrap break-all relative">
                  {job?.translatedHtml ? renderHighlighted(job.translatedHtml) : <span className="opacity-20 italic">Awaiting batch trigger...</span>}
                  {job?.status === 'error' && <p className="text-red-400 p-2 bg-red-500/10 rounded-lg text-[10px] mt-2 border border-red-500/20">{job.error}</p>}
                </div>
              </div>
            );
          })}
        </section>
      </main>

      <footer className="text-center py-4 border-t border-slate-900 mt-auto">
        <p className="text-[9px] font-black uppercase tracking-[0.6em] text-slate-700">Parallel Localization Engine &bull; Structural Parity Integrity &bull; Gemini 3 Pro Cluster</p>
      </footer>

      <style>{`
        @keyframes slideIn { from { transform: translateX(100%); } to { transform: translateX(0); } }
        .animate-slide-in { animation: slideIn 0.3s cubic-bezier(0.16, 1, 0.3, 1); }
        .animate-pulse-slow { animation: pulse 3s cubic-bezier(0.4, 0, 0.6, 1) infinite; }
        @keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: .7; } }
      `}</style>
    </div>
  );
};

