const LANGUAGES = [
  "English", "Spanish", "French", "German", "Chinese (Simplified)", 
  "Chinese (Traditional)", "Japanese", "Korean", "Portuguese", "Italian", 
  "Russian", "Arabic", "Hindi", "Turkish", "Dutch", "Polish", "Vietnamese",
  "Thai", "Indonesian", "Swedish", "Danish", "Finnish", "Norwegian",
  "Greek", "Czech", "Romanian", "Ukrainian", "Hebrew", "Malay"
];

interface TranslationJob {
  lang: string;
  translatedHtml: string;
  status: 'idle' | 'detecting' | 'translating' | 'completed' | 'error';
  progress: number;
  eta: number;
  error?: string;
}

interface ImageAsset {
  url: string;
  alt: string;
  type: 'img' | 'background';
  context: string;
  containsText: boolean | 'scanning' | 'failed' | null;
  detectionReasoning?: string;
}

const App: React.FC = () => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [sourceHtml, setSourceHtml] = useState<string>('<!-- Paste your HTML here -->\n<div class="hero">\n  <h1>Welcome to our website</h1>\n  <p>Discover the beauty of modern web localization.</p>\n  <img src="https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&q=80&w=2426" alt="Web analytics dashboard" />\n  <button title="Click to learn more">Get Started</button>\n</div>');
  const [selectedLangs, setSelectedLangs] = useState<string[]>(['Spanish']);
  const [detectedLang, setDetectedLang] = useState<string | null>(null);
  const [jobs, setJobs] = useState<Record<string, TranslationJob>>({});
