  const extractImagesFromHtml = () => {
    const images: ImageAsset[] = [];
    const parser = new DOMParser();
    const doc = parser.parseFromString(sourceHtml, 'text/html');
    const imgTags = doc.querySelectorAll('img');

    imgTags.forEach(img => {
      const src = img.getAttribute('src');
      const alt = img.getAttribute('alt') || '';
      if (src && !images.find(i => i.url === src)) {
        images.push({ 
          url: src, 
          alt, 
          type: 'img', 
          context: img.parentElement?.tagName.toLowerCase() || 'div',
          containsText: 'scanning'
        });
      }
    });

    const bgMatches = sourceHtml.match(/url\(['"]?(.*?)['"]?\)/g);
    if (bgMatches) {
      bgMatches.forEach(match => {
        const url = match.replace(/url\(['"]?(.*?)['"]?\)/, '$1');
        if (!images.find(i => i.url === url)) {
          images.push({ 
            url, 
            alt: 'Background Asset', 
            type: 'background', 
            context: 'css-style',
            containsText: 'scanning'
          });
        }
      });
    }
    return images;
  };

  const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = reject;
      reader.readAsDataURL(blob);
    });
  };

  const runVisionScan = async (asset: ImageAsset) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      let hasText = false;
      let reasoning = "";

      try {
        const imgRes = await fetch(asset.url, { mode: 'cors' });
        if (!imgRes.ok) throw new Error('Fetch failed');
        const blob = await imgRes.blob();
        const base64Data = await blobToBase64(blob);

        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: [{
            parts: [
              { inlineData: { data: base64Data, mimeType: blob.type || 'image/png' } },
              { text: "Does this image contain any legible text or words? Answer YES or NO and why." }
            ]
          }]
        });

        const output = response.text || "";
        hasText = output.toUpperCase().includes('YES');
        reasoning = output;
      } catch (fetchErr) {
        const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: [{ text: `Examine URL: ${asset.url}. Likely contains text? YES/NO.` }]
        });
        hasText = response.text?.toUpperCase().includes('YES') || false;
        reasoning = "CORS restriction; meta-analyzed.";
      }

      setDetectedImages(prev => prev.map(img => 
        img.url === asset.url ? { ...img, containsText: hasText, detectionReasoning: reasoning } : img
      ));
    } catch (e) {
      setDetectedImages(prev => prev.map(img => img.url === asset.url ? { ...img, containsText: 'failed' } : img));
    }
  };

  useEffect(() => {
    const initialImages = extractImagesFromHtml();
    setDetectedImages(initialImages);
    initialImages.forEach(img => runVisionScan(img));
  }, [sourceHtml]);

