  const runVisionScan = async (asset: ImageAsset) => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    try {
      const imgRes = await fetch(asset.url, { mode: 'cors' });
      if (!imgRes.ok) throw new Error('CORS');
      const blob = await imgRes.blob();
      const base64Data = await blobToBase64(blob);

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [{
          parts: [
            { inlineData: { data: base64Data, mimeType: blob.type || 'image/png' } },
            { text: "Does this image have text or logos? Reply 'YES' or 'NO' + reason." }
          ]
        }]
      });

      const text = response.text || "";
      setDetectedImages(prev => prev.map(img => 
        img.url === asset.url ? { ...img, containsText: text.toUpperCase().includes('YES'), detectionReasoning: text } : img
      ));
    } catch {
      setDetectedImages(prev => prev.map(img => 
        img.url === asset.url ? { ...img, containsText: 'failed', detectionReasoning: 'CORS/Load Error' } : img
      ));
    }
  };

  useEffect(() => {
    const freshAssets = extractImages();
    setDetectedImages(freshAssets);
    freshAssets.forEach(runVisionScan);
  }, [sourceHtml]);

  const triggerToast = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const cleanStreamedHtml = (text: string) => {
    // Robust cleaning for model-wrapped code blocks
    return text.replace(/```html\n?|```/g, '').trim();
  };

  const executeTranslation = async (lang: string, source: string, detected: string | null) => {
    setJobs(prev => ({ ...prev, [lang]: { lang, translatedHtml: '', status: 'translating', progress: 0 } }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: `Localize this HTML into ${lang}. Detected source: ${detected || 'auto'}. DO NOT change image URLs or IDs. Return ONLY the HTML code. Source:\n${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        fullText += chunk.text;
        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress: Math.min(95, (prev[lang].progress || 0) + 8)
          }
        }));
      }
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'completed', progress: 100 } }));
    } catch (err: any) {
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'error', error: err.message } }));
    }
  };

  const runBatch = async () => {
    if (!sourceHtml.trim() || selectedLangs.length === 0) return;
    setIsDetecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const res = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify primary language of this HTML: ${sourceHtml.substring(0, 400)}`,
      });
      const detected = res.text?.trim() || 'English';
      setDetectedLang(detected);
      selectedLangs.forEach(lang => executeTranslation(lang, sourceHtml, detected));
    } catch (e) { console.error(e); }
    setIsDetecting(false);
  };

  // UI Component for the Block-style progress (Activity View)
  const ActivityMatrix = ({ progress }: { progress: number }) => {
    const blocks = Array.from({ length: 12 });
    return (
      <div className="flex gap-1">
        {blocks.map((_, i) => {
          const threshold = (i / blocks.length) * 100;
          const isActive = progress > threshold;
          return (
            <div 
              key={i} 
              className={`h-4 w-2 rounded-sm transition-all duration-500 ${
                isActive ? 'bg-violet-500 shadow-[0_0_8px_rgba(139,92,246,0.5)]' : 'bg-zinc-200 dark:bg-zinc-800'
              }`}
            />
          );
        })}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-white dark:bg-[#070707] text-[#111] dark:text-[#eee] transition-all duration-500 font-sans selection:bg-violet-500/40">

      {showNotification && (
        <div className="fixed top-8 right-8 z-[200] animate-in slide-in-from-right fade-in duration-500">
          <div className="bg-[#111] dark:bg-zinc-900 text-white px-6 py-4 rounded-3xl shadow-2xl border border-white/10 flex items-center gap-4">
            <div className="w-2 h-2 rounded-full bg-violet-400 animate-pulse" />
            <span className="text-sm font-bold tracking-tight">{showNotification}</span>
          </div>
        </div>
      )}

      <nav className="max-w-[1700px] mx-auto px-8 py-8 flex items-center justify-between">
        <div className="flex items-center gap-14">
          <div className="flex items-center gap-4">
             <div className="w-11 h-11 rounded-[14px] bg-gradient-to-br from-violet-600 to-indigo-500 flex items-center justify-center shadow-2xl shadow-violet-500/30">
                <span className="text-white font-black text-2xl tracking-tighter">L</span>
             </div>
             <span className="text-2xl font-black tracking-tighter uppercase dark:text-white">LOKALYZE<span className="text-violet-500">.SITE</span></span>
          </div>
          <div className="hidden lg:flex items-center gap-10 text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400 dark:text-zinc-600">
            <button className="text-violet-500 hover:text-violet-400">Hub</button>
            <button className="hover:text-black dark:hover:text-white">Media</button>
            <button className="hover:text-black dark:hover:text-white">History</button>
            <button className="hover:text-black dark:hover:text-white">API</button>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="w-12 h-12 rounded-full border border-zinc-200 dark:border-zinc-800 flex items-center justify-center hover:scale-110 transition-transform">
            {theme === 'dark' ? '☼' : '☾'}
          </button>
          <div className="h-10 w-[1px] bg-zinc-800 hidden md:block" />
          <div className="flex items-center gap-4">
             <div className="text-right hidden sm:block">
                <p className="text-xs font-bold dark:text-white">Angela Dev</p>
                <p className="text-[9px] font-black uppercase tracking-widest text-violet-500">Pro Tier</p>
             </div>
             <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Angela" className="w-12 h-12 rounded-2xl bg-zinc-100 dark:bg-zinc-900 border border-white/5" alt="User" />
          </div>
        </div>
      </nav>

      <main className="max-w-[1700px] mx-auto px-8 pb-32 grid grid-cols-1 xl:grid-cols-12 gap-10">

        {/* Workspace */}
        <div className="xl:col-span-8 flex flex-col gap-10">
          <div className="flex flex-col gap-2">
            <h1 className="text-5xl font-black tracking-tighter dark:text-white leading-[0.9]">Intelligence<br/><span className="text-zinc-400 dark:text-zinc-800">Dashboard</span></h1>
            <div className="flex items-center gap-6 mt-6">
               <div className="flex items-center gap-3 bg-zinc-100 dark:bg-[#111] px-5 py-2.5 rounded-2xl border border-zinc-200 dark:border-white/5">
