                  disabled={isDetecting || selectedLangs.length === 0}
                  className="bg-violet-600 hover:bg-violet-500 text-white px-12 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] shadow-2xl shadow-violet-600/20 active:scale-95 disabled:opacity-20 transition-all"
                >
