          {/* Results Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {selectedLangs.map(lang => {
              const job = jobs[lang];
              return (
                <div key={lang} className="bg-white dark:bg-[#111] rounded-[40px] p-8 border border-zinc-200 dark:border-white/5 shadow-xl transition-all group overflow-hidden">
                  <div className="flex items-center justify-between mb-8">
