                    {job?.translatedHtml && (
                      <button onClick={() => { navigator.clipboard.writeText(job.translatedHtml); triggerToast(`${lang} Copied`); }} className="w-12 h-12 rounded-2xl bg-zinc-50 dark:bg-[#070707] flex items-center justify-center hover:bg-violet-600 hover:text-white transition-all">
                        📋
                      </button>
                    )}
                  </div>

                  <div className="mb-6 flex items-center justify-between">
                    <ActivityMatrix progress={job?.progress || 0} />
                    <span className="text-[10px] font-black text-zinc-400">{job?.progress || 0}%</span>
                  </div>

                  <div className="bg-zinc-50 dark:bg-black/40 rounded-3xl p-6 h-[220px] overflow-y-auto code-font text-[11px] text-zinc-500 dark:text-zinc-400 border border-zinc-200 dark:border-white/5 custom-scrollbar">
                    {job?.translatedHtml || <span className="opacity-20 italic">Awaiting batch signal...</span>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Sidebar */}
        <div className="xl:col-span-4 flex flex-col gap-10">

          {/* Target Selector */}
          <div className="bg-white dark:bg-[#111] rounded-[40px] p-10 border border-zinc-200 dark:border-white/5 shadow-2xl">
            <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400 mb-8 flex items-center gap-3">
              <span className="w-2 h-2 rounded-full bg-violet-500" />
              Target Locales
            </h3>
            <div className="flex flex-wrap gap-2.5 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar">
              {LANGUAGES.map(lang => (
                <button
                  key={lang}
                  onClick={() => setSelectedLangs(prev => prev.includes(lang) ? prev.filter(l => l !== lang) : [...prev, lang])}
                  className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border ${
                    selectedLangs.includes(lang) 
                    ? 'bg-violet-600 border-violet-500 text-white shadow-xl shadow-violet-600/30' 
                    : 'bg-zinc-100 dark:bg-[#070707] border-zinc-200 dark:border-zinc-800 text-zinc-500 hover:border-violet-500/50'
                  }`}
                >
                  {lang}
                </button>
              ))}
            </div>
          </div>

          {/* Media Lab Sidebar */}
          <div className={`bg-white dark:bg-[#111] rounded-[40px] p-10 border border-zinc-200 dark:border-white/5 transition-all duration-700 ${showMediaLab ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-4 pointer-events-none'}`}>
             <div className="flex items-center justify-between mb-10">
               <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400">Media Intelligence</h3>
               <span className="bg-lime-400/20 text-lime-600 dark:text-lime-400 text-[9px] px-3 py-1 rounded-full font-black uppercase tracking-tighter shadow-sm">{detectedImages.length} Active</span>
             </div>

             <div className="flex flex-col gap-8">
                {detectedImages.map((asset, i) => (
                  <div key={i} className="flex gap-5 items-center group">
                    <div className="w-20 h-20 rounded-3xl bg-zinc-100 dark:bg-black overflow-hidden border border-zinc-200 dark:border-white/5 relative shadow-lg">
                       <img src={asset.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-90 group-hover:opacity-100" alt="" />
                       {asset.containsText === 'scanning' && (
                         <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center">
                           <div className="w-4 h-4 border-2 border-violet-500 border-t-transparent rounded-full animate-spin" />
                         </div>
                       )}
                    </div>
                    <div className="flex-grow min-w-0">
                       <div className="flex items-center justify-between mb-1.5">
                          <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full tracking-wider border ${
                            asset.containsText === true ? 'bg-orange-500/10 border-orange-500/30 text-orange-500' : 
                            asset.containsText === false ? 'bg-lime-500/10 border-lime-500/30 text-lime-500' : 'bg-zinc-800 text-zinc-500 border-white/5'
                          }`}>
                            {asset.containsText === true ? 'Edit Required' : asset.containsText === 'scanning' ? 'Scanning...' : 'Graphic OK'}
                          </span>
                       </div>
                       <p className="text-[10px] font-mono text-zinc-500 dark:text-zinc-600 truncate">{asset.url}</p>
                       <p className="text-[9px] text-zinc-400 dark:text-zinc-700 font-medium italic mt-1 line-clamp-1">"{asset.detectionReasoning || 'Analyzing pixels...'}"</p>
                    </div>
                  </div>
                ))}
                {detectedImages.length === 0 && <p className="text-center text-xs text-zinc-600 italic py-10 opacity-30">No assets detected in buffer</p>}
             </div>
          </div>
        </div>
      </main>

      <footer className="max-w-[1700px] mx-auto px-8 py-20 border-t border-zinc-200 dark:border-zinc-900 flex flex-col md:flex-row justify-between items-center gap-6 opacity-30 group hover:opacity-100 transition-opacity">
        <p className="text-[9px] font-black uppercase tracking-[0.5em]">&copy; 2025 LOKALYZE.SITE &bull; PRECISION LOCALIZATION ENGINE</p>
        <div className="flex gap-10 text-[9px] font-black uppercase tracking-[0.3em]">
           <button className="hover:text-violet-500 transition-colors">Documentation</button>
           <button className="hover:text-violet-500 transition-colors">Privacy Shield</button>
           <button className="hover:text-violet-500 transition-colors">System Status</button>
        </div>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #222; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #333; }
        textarea::selection { background: #8b5cf6; color: white; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fadeUp 0.5s ease-out forwards; }
      `}</style>
    </div>
  );
};

const rootElement = document.getElementById('root');
if (rootElement) {
