                return (
                  <button
                    key={lang}
                    disabled={isBatchRunning}
                    onClick={() => setSelectedLangs(prev => isSelected ? prev.filter(l => l !== lang) : [...prev, lang])}
                    className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border relative overflow-hidden group ${
                      isSelected 
                      ? 'bg-violet-600 border-violet-500 text-white shadow-xl shadow-violet-600/20' 
                      : 'bg-zinc-100 dark:bg-[#070707] border-zinc-200 dark:border-zinc-800 text-zinc-500 hover:border-violet-500/50'
                    } ${isBatchRunning ? 'opacity-50 cursor-not-allowed' : ''}`}
                  >
                    {lang}
                    {hasJob?.status === 'completed' && <span className="ml-2">✓</span>}
