               </div>
               <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-zinc-500">
                  <span>Estimated API Calls</span>
                  <span className="text-white">{selectedLangs.length + 1}</span>
               </div>
            </div>
          </div>

          {/* Media Intelligence (Evolved) */}
          <div className={`bg-white dark:bg-[#111] rounded-[48px] p-10 border border-zinc-200 dark:border-white/5 transition-all duration-700 ${showMediaLab ? 'opacity-100' : 'hidden opacity-0'}`}>
             <div className="flex items-center justify-between mb-10">
               <h3 className="text-[10px] font-black uppercase tracking-[0.35em] text-zinc-400">Media Vault</h3>
               <span className="bg-lime-400 text-black text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-tight shadow-lg shadow-lime-400/20">{detectedImages.length} Identified</span>
             </div>

             <div className="flex flex-col gap-10">
                {detectedImages.map((asset, i) => (
                  <div key={i} className="flex gap-6 items-start group">
                    <div className="w-24 h-24 rounded-[32px] bg-zinc-100 dark:bg-black overflow-hidden border border-zinc-200 dark:border-white/5 relative shadow-2xl flex-shrink-0">
                       <img src={asset.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 opacity-90 group-hover:opacity-100" alt="" />
                       {asset.containsText === 'scanning' && (
                         <div className="absolute inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center">
                           <div className="w-5 h-5 border-2 border-violet-500 border-t-transparent rounded-full animate-spin" />
