import React, { useState, useRef, useEffect, useMemo } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const LANGUAGES = [
  "English", "Spanish", "French", "German", "Chinese (Simplified)", 
  "Chinese (Traditional)", "Japanese", "Korean", "Portuguese", "Italian", 
  "Russian", "Arabic", "Hindi", "Turkish", "Dutch", "Polish", "Vietnamese",
  "Thai", "Indonesian", "Swedish", "Danish", "Finnish", "Norwegian",
  "Greek", "Czech", "Romanian", "Ukrainian", "Hebrew", "Malay"
];

const MAX_CONCURRENT_JOBS = 3;

interface TranslationJob {
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
  startTime?: number;
}

interface ImageAsset {
  url: string;
  alt: string;
  type: 'img' | 'background';
  context: string;
  containsText: boolean | 'scanning' | 'failed' | null;
  detectionReasoning?: string;
}

const App: React.FC = () => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [sourceHtml, setSourceHtml] = useState<string>('<!-- Paste your HTML here -->\n<div class="hero">\n  <h1>Global Expansion Starts Here</h1>\n  <p>LOKALYZE.SITE handles your complex DOM structures with precision.</p>\n  <img src="https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&q=80&w=2426" alt="Dashboard Preview" />\n</div>');
  const [selectedLangs, setSelectedLangs] = useState<string[]>(['Spanish', 'French']);
  const [detectedLang, setDetectedLang] = useState<string | null>(null);
  const [jobs, setJobs] = useState<Record<string, TranslationJob>>({});
  const [isBatchRunning, setIsBatchRunning] = useState<boolean>(false);
  const [showNotification, setShowNotification] = useState<string | null>(null);
  const [showMediaLab, setShowMediaLab] = useState<boolean>(false);
  const [detectedImages, setDetectedImages] = useState<ImageAsset[]>([]);
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);

  // Refs to prevent race conditions in the queue
  const processingRefs = useRef<Set<string>>(new Set());

  useEffect(() => {
    document.documentElement.className = theme;
    checkApiKeyStatus();
  }, [theme]);

  const checkApiKeyStatus = async () => {
    // @ts-ignore
    if (window.aistudio?.hasSelectedApiKey) {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(hasKey);
    }
  };

  const triggerToast = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  // Helper to ensure we always use the freshest key from the environment
  const getAiClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API Key not found. Please click 'API Integration'.");
    }
    return new GoogleGenAI({ apiKey });
  };

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    if (window.aistudio?.openSelectKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
      // Assume success after trigger to mitigate race condition
      setHasApiKey(true);
      triggerToast("Engine Synchronized");
    }
  };

  const extractImages = () => {
    const images: ImageAsset[] = [];
    const parser = new DOMParser();
    const doc = parser.parseFromString(sourceHtml, 'text/html');
    doc.querySelectorAll('img').forEach(img => {
      const src = img.getAttribute('src');
      if (src && !images.find(i => i.url === src)) {
        images.push({ url: src, alt: img.getAttribute('alt') || '', type: 'img', context: 'img-tag', containsText: 'scanning' });
      }
    });
    return images;
  };

  const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(blob);
    });
  };

  const runVisionScan = async (asset: ImageAsset) => {
    try {
      const ai = getAiClient();
      const imgRes = await fetch(asset.url, { mode: 'cors' });
      if (!imgRes.ok) throw new Error('CORS_BLOCKED');
      const blob = await imgRes.blob();
      const base64Data = await blobToBase64(blob);

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: [{
          parts: [
            { inlineData: { data: base64Data, mimeType: blob.type || 'image/png' } },
            { text: "Does this image contain legible text? YES or NO." }
          ]
        }]
      });

      const result = response.text || "";
      setDetectedImages(prev => prev.map(img => 
        img.url === asset.url ? { ...img, containsText: result.toUpperCase().includes('YES'), detectionReasoning: result } : img
      ));
    } catch (e: any) {
      setDetectedImages(prev => prev.map(img => img.url === asset.url ? { ...img, containsText: 'failed', detectionReasoning: e.message === 'CORS_BLOCKED' ? 'Access Denied (CORS)' : 'Scanner Offline' } : img));
    }
  };

  useEffect(() => {
    const freshAssets = extractImages();
    setDetectedImages(freshAssets);
    // Only scan if we have an API key context
    if (process.env.API_KEY) {
      freshAssets.forEach(runVisionScan);
    }
  }, [sourceHtml]);

  const cleanStreamedHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();

  const executeTranslation = async (lang: string, source: string, detected: string | null) => {
    if (processingRefs.current.has(lang)) return;
    processingRefs.current.add(lang);

    setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'translating', startTime: Date.now(), error: undefined } }));

    try {
      const ai = getAiClient();
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: `Translate this HTML to ${lang}. Detect source: ${detected || 'auto'}. Preserving all tags/IDs exactly. Source: ${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        fullText += chunk.text;
        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress: Math.min(98, (prev[lang].progress || 0) + 4)
          }
        }));
      }
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'completed', progress: 100 } }));
    } catch (err: any) {
      console.error(`Translation failed for ${lang}:`, err);
      let errorMsg = err.message || "Engine Error";
      if (errorMsg.includes("Requested entity was not found")) {
        errorMsg = "API Key Invalid or Expired";
        setHasApiKey(false);
      }
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'error', error: errorMsg } }));
    } finally {
      processingRefs.current.delete(lang);
    }
  };

  // Queue Controller Logic
  useEffect(() => {
    const jobList = Object.values(jobs) as TranslationJob[];
    const activeJobs = jobList.filter(j => j.status === 'translating');
    const queuedJobs = jobList.filter(j => j.status === 'queued');

    if (activeJobs.length < MAX_CONCURRENT_JOBS && queuedJobs.length > 0) {
      const nextJob = queuedJobs[0];
      executeTranslation(nextJob.lang, sourceHtml, detectedLang);
    }

    if (activeJobs.length === 0 && queuedJobs.length === 0 && isBatchRunning) {
      const hasErrors = jobList.some(j => j.status === 'error');
      setIsBatchRunning(false);
      triggerToast(hasErrors ? "Batch completed with errors" : "Batch Finalized");
    }
  }, [jobs, isBatchRunning]);

  const startQueue = async () => {
    if (!sourceHtml.trim() || selectedLangs.length === 0) return;

    if (!process.env.API_KEY) {
      await handleOpenKeySelector();
      return;
    }

    setIsBatchRunning(true);
    processingRefs.current.clear();

    try {
      const ai = getAiClient();
      const res = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify source language (name only): ${sourceHtml.substring(0, 300)}`,
      });
      setDetectedLang(res.text?.trim() || 'English');
    } catch (e) { 
      console.error("Lang Detection Failed", e);
    }

    const initialJobs: Record<string, TranslationJob> = {};
    selectedLangs.forEach(lang => {
      initialJobs[lang] = { lang, translatedHtml: '', status: 'queued', progress: 0 };
    });
    setJobs(initialJobs);
  };

  const retryJob = (lang: string) => {
    setJobs(prev => ({
      ...prev,
      [lang]: { ...prev[lang], status: 'queued', progress: 0, error: undefined }
    }));
  };

  const ActivityMatrix = ({ progress, status }: { progress: number, status: string }) => {
    const blocks = Array.from({ length: 12 });
    return (
      <div className="flex gap-1">
        {blocks.map((_, i) => {
          const isActive = progress > (i / blocks.length) * 100;
          return (
            <div key={i} className={`h-4 w-2 rounded-sm transition-all duration-700 ${
              status === 'error' ? 'bg-red-500/20' :
              isActive ? status === 'completed' ? 'bg-lime-500' : 'bg-violet-500 shadow-[0_0_8px_rgba(139,92,246,0.5)]' : 'bg-zinc-200 dark:bg-zinc-800'
            }`} />
          );
        })}
      </div>
    );
  };

  const globalProgress = useMemo(() => {
    const vals = Object.values(jobs) as TranslationJob[];
    return vals.length ? Math.round(vals.reduce((acc, curr) => acc + curr.progress, 0) / vals.length) : 0;
  }, [jobs]);

  return (
    <div className="min-h-screen bg-white dark:bg-[#070707] text-[#111] dark:text-[#eee] transition-all duration-500 font-sans selection:bg-violet-500/40">
      {showNotification && (
        <div className="fixed top-8 right-8 z-[200] animate-in slide-in-from-right fade-in duration-500">
          <div className="bg-zinc-900 text-white px-6 py-4 rounded-3xl shadow-2xl border border-white/10 flex items-center gap-4">
            <div className="w-2 h-2 rounded-full bg-violet-400 animate-pulse" />
            <span className="text-sm font-bold tracking-tight">{showNotification}</span>
          </div>
        </div>
      )}

      <nav className="max-w-[1700px] mx-auto px-8 py-8 flex items-center justify-between">
        <div className="flex items-center gap-14">
          <div className="flex items-center gap-4">
             <div className="w-11 h-11 rounded-[14px] bg-gradient-to-br from-violet-600 to-indigo-500 flex items-center justify-center shadow-2xl shadow-violet-500/30">
                <span className="text-white font-black text-2xl tracking-tighter italic">L</span>
             </div>
             <span className="text-2xl font-black tracking-tighter uppercase dark:text-white">LOKALYZE<span className="text-violet-500">.SITE</span></span>
          </div>
          <div className="hidden lg:flex items-center gap-10 text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400 dark:text-zinc-600">
            <button onClick={() => setShowMediaLab(false)} className={`${!showMediaLab ? 'text-violet-500' : 'hover:text-black dark:hover:text-white'}`}>Workspace</button>
            <button onClick={() => setShowMediaLab(true)} className={`${showMediaLab ? 'text-violet-500' : 'hover:text-black dark:hover:text-white'}`}>Asset Intelligence</button>
            <button onClick={handleOpenKeySelector} className="hover:text-black dark:hover:text-white flex items-center gap-2">
              API Integration
              {!hasApiKey && <span className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse"></span>}
            </button>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="w-12 h-12 rounded-full border border-zinc-200 dark:border-zinc-800 flex items-center justify-center hover:scale-110 transition-transform">
            {theme === 'dark' ? '☼' : '☾'}
          </button>
          <div className="h-10 w-[1px] bg-zinc-800 hidden md:block" />
          <div className="flex items-center gap-4">
             <div className="text-right hidden sm:block">
                <p className="text-xs font-bold dark:text-white">Angela Dev</p>
                <p className="text-[9px] font-black uppercase tracking-widest text-violet-500">BATCH CONCURRENCY: {MAX_CONCURRENT_JOBS}X</p>
             </div>
             <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Angela" className="w-12 h-12 rounded-2xl bg-zinc-100 dark:bg-zinc-900 border border-white/5" alt="User" />
          </div>
        </div>
      </nav>

      <main className="max-w-[1700px] mx-auto px-8 pb-32 grid grid-cols-1 xl:grid-cols-12 gap-10">
        <div className="xl:col-span-8 flex flex-col gap-10">
          {!showMediaLab ? (
            <>
              <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 animate-in">
                <div className="flex flex-col gap-2">
                  <h1 className="text-6xl font-black tracking-tighter dark:text-white leading-[0.85]">Parallel<br/><span className="text-zinc-400 dark:text-zinc-800 italic">Queue Engine</span></h1>
                  <div className="flex items-center gap-6 mt-8">
                    <div className="flex items-center gap-3 bg-zinc-100 dark:bg-[#111] px-5 py-2.5 rounded-2xl border border-zinc-200 dark:border-white/5">
                        <div className={`w-2 h-2 rounded-full ${isBatchRunning ? 'bg-violet-500 animate-ping' : 'bg-lime-400 shadow-[0_0_8px_rgba(163,230,53,0.5)]'}`} />
                        <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">{isBatchRunning ? 'Batch Active' : 'System Ready'}</span>
                    </div>
