import React, { useState, useRef, useEffect, useMemo } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese (Simplified)", 
  "Japanese", "Korean", "Portuguese", "Italian", 
  "Russian", "Arabic", "Hindi", "Dutch", "Turkish"
];

const MAX_CONCURRENT_JOBS = 2;

interface TranslationJob {
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
}

const App: React.FC = () => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [sourceHtml, setSourceHtml] = useState<string>('<!-- Paste HTML here -->\n<div class="hero">\n  <h1>Expand your horizons</h1>\n  <p>Lokalyze translates complex structures while keeping your design intact.</p>\n</div>');
  const [selectedLangs, setSelectedLangs] = useState<string[]>(['Spanish', 'French']);
  const [jobs, setJobs] = useState<Record<string, TranslationJob>>({});
  const [isBatchRunning, setIsBatchRunning] = useState<boolean>(false);
  const [showNotification, setShowNotification] = useState<string | null>(null);

  const processingRefs = useRef<Set<string>>(new Set());

  useEffect(() => {
    document.documentElement.className = theme;
  }, [theme]);

  const triggerToast = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const getAiClient = async () => {
    // Check if user has selected a key (required for Gemini 3 Pro)
    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  };

  const cleanHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();

  const executeTranslation = async (lang: string, source: string) => {
    if (processingRefs.current.has(lang)) return;
    processingRefs.current.add(lang);

    setJobs(prev => ({
      ...prev,
      [lang]: { ...prev[lang], status: 'translating', error: undefined }
    }));

    try {
      const ai = await getAiClient();
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: `Translate this HTML perfectly into ${lang}. 
        CRITICAL: Keep all CSS, IDs, Classes, and Script tags exactly as they are. 
        Only translate the visible text content and alt attributes. 
        Return ONLY the raw HTML code.
        Source HTML:
        ${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        fullText += chunk.text;
        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: cleanHtml(fullText),
            progress: Math.min(95, (prev[lang].progress || 0) + 5)
          }
        }));
      }

      setJobs(prev => ({ 
        ...prev, 
        [lang]: { ...prev[lang], status: 'completed', progress: 100 } 
      }));
    } catch (err: any) {
      console.error(err);
      setJobs(prev => ({ 
        ...prev, 
        [lang]: { ...prev[lang], status: 'error', error: err.message || "Translation failed" } 
      }));
    } finally {
      processingRefs.current.delete(lang);
    }
  };

  // Orchestrator: Watch for queued jobs and process them based on concurrency limit
  useEffect(() => {
    const jobList = Object.values(jobs);
    const active = jobList.filter(j => j.status === 'translating');
    const queued = jobList.filter(j => j.status === 'queued');

    if (active.length < MAX_CONCURRENT_JOBS && queued.length > 0) {
      const next = queued[0];
      executeTranslation(next.lang, sourceHtml);
    }

    if (isBatchRunning && active.length === 0 && queued.length === 0) {
      setIsBatchRunning(false);
      triggerToast("All translations complete");
    }
  }, [jobs, isBatchRunning]);

  const startBatch = async () => {
    if (!sourceHtml.trim()) return triggerToast("Paste some HTML first");
    if (selectedLangs.length === 0) return triggerToast("Select target languages");

    setIsBatchRunning(true);
    processingRefs.current.clear();

    const initialJobs: Record<string, TranslationJob> = {};
    selectedLangs.forEach(lang => {
      initialJobs[lang] = { lang, translatedHtml: '', status: 'queued', progress: 0 };
    });
    setJobs(initialJobs);
  };

  const copyToClipboard = (text: string, lang: string) => {
    navigator.clipboard.writeText(text);
    triggerToast(`${lang} copied to clipboard`);
  };

  return (
    <div className="min-h-screen bg-[#fcfcfc] dark:bg-[#0a0a0a] text-zinc-900 dark:text-zinc-100 transition-colors duration-300 font-sans">
      {/* Toast */}
      {showNotification && (
        <div className="fixed top-6 right-6 z-50 animate-bounce">
          <div className="bg-violet-600 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-sm">
            {showNotification}
          </div>
        </div>
      )}

      {/* Header */}
      <header className="border-b border-zinc-200 dark:border-zinc-800 py-6 px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-violet-600 rounded-xl flex items-center justify-center font-black text-white italic shadow-lg">L</div>
            <h1 className="text-xl font-black tracking-tighter uppercase">Lokalyze<span className="text-violet-600">.site</span></h1>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
              className="p-3 rounded-xl border border-zinc-200 dark:border-zinc-800 hover:bg-zinc-100 dark:hover:bg-zinc-900 transition-colors"
            >
              {theme === 'dark' ? '☀️' : '🌙'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-8 py-12 grid grid-cols-1 lg:grid-cols-12 gap-12">
        {/* Left: Input & Editor */}
        <div className="lg:col-span-8 space-y-8">
          <div className="space-y-4">
            <div className="flex justify-between items-end">
              <div>
                <h2 className="text-4xl font-black tracking-tight">Parallel <span className="text-violet-600">Queue</span></h2>
                <p className="text-zinc-500 text-sm mt-1">Paste your HTML source below to begin localization.</p>
              </div>
              <button 
                onClick={startBatch}
                disabled={isBatchRunning}
                className="bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white px-8 py-4 rounded-2xl font-bold text-sm uppercase tracking-widest shadow-xl shadow-violet-600/20 transition-all active:scale-95"
              >
                {isBatchRunning ? 'Processing...' : 'Deploy Queue'}
              </button>
            </div>

            <div className="relative group">
              <textarea 
                value={sourceHtml}
                onChange={(e) => setSourceHtml(e.target.value)}
                className="w-full h-[400px] bg-white dark:bg-[#111] border border-zinc-200 dark:border-zinc-800 rounded-3xl p-8 code-font text-sm outline-none focus:ring-2 ring-violet-600/20 transition-all resize-none shadow-sm"
                placeholder="Paste original HTML here..."
              />
            </div>
          </div>

          {/* Results Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {Object.values(jobs).map(job => (
              <div key={job.lang} className={`p-6 rounded-[32px] border transition-all ${
                job.status === 'error' ? 'border-red-500/30 bg-red-500/5' : 
                job.status === 'completed' ? 'border-emerald-500/30 bg-emerald-500/5' :
                'border-zinc-200 dark:border-zinc-800 bg-white dark:bg-[#111]'
              }`}>
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h3 className="font-bold text-lg">{job.lang}</h3>
                    <p className={`text-[10px] uppercase font-black tracking-widest ${
                      job.status === 'translating' ? 'text-violet-500 animate-pulse' : 
                      job.status === 'error' ? 'text-red-500' : 'text-zinc-500'
                    }`}>
                      {job.status === 'queued' ? 'In Queue' : job.status}
                    </p>
                  </div>
                  {job.status === 'completed' && (
                    <button 
                      onClick={() => copyToClipboard(job.translatedHtml, job.lang)}
                      className="p-2 hover:bg-emerald-500/20 rounded-lg transition-colors"
                      title="Copy HTML"
                    >
                      📋
                    </button>
                  )}
                </div>

                <div className="h-1 bg-zinc-100 dark:bg-zinc-800 rounded-full mb-4 overflow-hidden">
                  <div 
                    className={`h-full transition-all duration-500 ${job.status === 'error' ? 'bg-red-500' : 'bg-violet-600'}`} 
                    style={{ width: `${job.progress}%` }} 
                  />
                </div>

                <div className="h-40 bg-zinc-50 dark:bg-black/40 rounded-2xl p-4 overflow-y-auto border border-zinc-200 dark:border-zinc-800">
                  {job.status === 'error' ? (
                    <p className="text-red-500 text-xs font-mono">{job.error}</p>
                  ) : (
                    <pre className="text-[10px] code-font text-zinc-400 whitespace-pre-wrap">
                      {job.translatedHtml || 'Awaiting slot...'}
                    </pre>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Right: Language Selector */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-white dark:bg-[#111] border border-zinc-200 dark:border-zinc-800 rounded-[40px] p-8 shadow-sm sticky top-12">
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-400 mb-6">Target Languages</h3>
            <div className="flex flex-wrap gap-2">
              {LANGUAGES.map(lang => (
                <button
                  key={lang}
                  onClick={() => setSelectedLangs(prev => 
                    prev.includes(lang) ? prev.filter(l => l !== lang) : [...prev, lang]
                  )}
                  className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border ${
                    selectedLangs.includes(lang) 
                    ? 'bg-violet-600 border-violet-600 text-white shadow-lg shadow-violet-600/20' 
                    : 'bg-zinc-50 dark:bg-zinc-900 border-zinc-200 dark:border-zinc-800 text-zinc-500 hover:border-violet-600/50'
                  }`}
                >
                  {lang}
                </button>
              ))}
            </div>

            <div className="mt-8 pt-8 border-t border-zinc-100 dark:border-zinc-800">
               <div className="flex justify-between items-center text-sm font-bold">
                  <span className="text-zinc-500">Selected</span>
                  <span className="text-violet-600">{selectedLangs.length}</span>
               </div>
               <p className="text-[10px] text-zinc-400 mt-2 uppercase tracking-widest font-bold">Limit: 2 Parallel Streams</p>
