  "Russian", "Arabic", "Hindi", "Turkish", "Dutch", "Polish", "Vietnamese",
  "Thai", "Indonesian", "Swedish", "Danish", "Finnish", "Norwegian",
  "Greek", "Czech", "Romanian", "Ukrainian", "Hebrew", "Malay"
];

const MAX_CONCURRENT_JOBS = 3;

interface TranslationJob {
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
  startTime?: number;
  estimatedSecondsLeft?: number;
  viewMode: 'code' | 'preview';
}

interface ImageAsset {
  url: string;
  alt: string;
  type: 'img' | 'background';
  context: string;
  containsText: boolean | 'scanning' | 'failed' | null;
  detectionReasoning?: string;
}

const App: React.FC = () => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [sourceHtml, setSourceHtml] = useState<string>('<!-- Paste your HTML here -->\n<div class="hero" style="padding: 40px; text-align: center; font-family: sans-serif;">\n  <h1 style="color: #8b5cf6;">Global Expansion Starts Here</h1>\n  <p>LOKALYZE.SITE handles your complex DOM structures with precision.</p>\n  <img src="https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&q=80&w=400" alt="Dashboard" style="border-radius: 20px; width: 100%; max-width: 300px;" />\n</div>');
  const [selectedLangs, setSelectedLangs] = useState<string[]>(['Spanish', 'French', 'German']);
  const [detectedLang, setDetectedLang] = useState<string | null>(null);
  const [jobs, setJobs] = useState<Record<string, TranslationJob>>({});
  const [isBatchRunning, setIsBatchRunning] = useState<boolean>(false);
  const [showNotification, setShowNotification] = useState<string | null>(null);
  const [showMediaLab, setShowMediaLab] = useState<boolean>(false);
  const [detectedImages, setDetectedImages] = useState<ImageAsset[]>([]);

  useEffect(() => {
    document.documentElement.className = theme;
  }, [theme]);

  const triggerToast = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const cleanStreamedHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();

  const executeTranslation = async (lang: string, source: string, detected: string | null) => {
    const startTime = Date.now();
    setJobs(prev => ({ 
      ...prev, 
      [lang]: { ...prev[lang], status: 'translating', startTime, estimatedSecondsLeft: 0, viewMode: 'code' } 
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `Localize this HTML into ${lang}. Detected source: ${detected || 'auto'}. Keep structure, CSS, and IDs exactly. Return ONLY the HTML code.\nSource:\n${source}`,
      });

      let fullText = '';
      const sourceLength = source.length;

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        fullText += c.text;

        const currentLength = fullText.length;
        const elapsed = (Date.now() - startTime) / 1000;
        const charsPerSec = currentLength / elapsed;
        const remainingChars = Math.max(0, sourceLength - currentLength);
        const estimatedSecondsLeft = Math.round(remainingChars / charsPerSec);

        // Progress is based on total characters received vs expected (roughly 1:1 with source for HTML)
        const progress = Math.min(99, Math.round((currentLength / sourceLength) * 100));

        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress,
            estimatedSecondsLeft
          }
        }));
      }
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'completed', progress: 100, estimatedSecondsLeft: 0 } }));
      triggerToast(`${lang} Translation Ready`);
    } catch (err: any) {
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'error', error: err.message } }));
