          <div className="bg-white dark:bg-[#0e0e0e] rounded-[48px] p-10 border border-zinc-200 dark:border-white/5 shadow-2xl relative overflow-hidden group">
            <div className="flex flex-col gap-8">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <button onClick={() => setSourceHtml('')} className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400 hover:text-red-500 transition-colors">Reset Input</button>
                  <div className="h-4 w-px bg-zinc-200 dark:bg-zinc-800" />
                  <span className="text-[9px] font-black uppercase tracking-widest text-zinc-300 dark:text-zinc-600 flex items-center gap-2">
                    <div className={`w-1.5 h-1.5 rounded-full ${isSaving ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500'}`} />
                    {isSaving ? 'Syncing...' : 'Autosaved'}
