                <div className="flex gap-4">
                  <button onClick={() => setFullScreenPreview({html: sourceHtml, title: 'Original'})} className="px-6 py-5 rounded-[24px] text-[12px] font-black uppercase tracking-[0.2em] border border-zinc-200 dark:border-zinc-800 hover:bg-zinc-50 dark:hover:bg-zinc-900 transition-all">Expand Preview</button>
                  <button onClick={startQueue} disabled={isBatchRunning || selectedLangs.length === 0} className="bg-[#111] dark:bg-white dark:text-black text-white px-16 py-5 rounded-[24px] text-[12px] font-black uppercase tracking-[0.2em] shadow-2xl hover:bg-violet-600 dark:hover:bg-violet-500 dark:hover:text-white transition-all disabled:opacity-30">Deploy Queue</button>
