                      {job.status === 'translating' ? `⚡ Streaming (~${job.estimatedSecondsLeft}s)` : job.status === 'completed' ? '✓ Ready' : '◷ Queued'}
                    </p>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => setFullScreenPreview({html: job.translatedHtml, title: job.lang})} className="w-11 h-11 rounded-2xl bg-zinc-100 dark:bg-zinc-900 flex items-center justify-center text-zinc-400 hover:text-zinc-600 transition-all">⤢</button>
                    <button onClick={() => setJobs(prev => ({...prev, [job.lang]: {...prev[job.lang], viewMode: prev[job.lang].viewMode === 'code' ? 'preview' : 'code'}}))} className={`w-11 h-11 rounded-2xl flex items-center justify-center transition-all ${job.viewMode === 'preview' ? 'bg-violet-600 text-white' : 'bg-zinc-100 dark:bg-zinc-900 text-zinc-400'}`}>{job.viewMode === 'preview' ? '👁' : '‹›'}</button>
