                outline-offset: -2px;
                cursor: crosshair;
              }
              .lokalyze-hover::after {
                content: attr(data-tag);
                position: absolute;
                top: 0; left: 0;
                background: #8b5cf6;
                color: white;
                font-size: 8px;
                padding: 1px 4px;
                z-index: 99999;
                font-family: monospace;
                pointer-events: none;
              }
            </style>
            <script>
