                el.classList.add('lokalyze-hover');
                el.setAttribute('data-tag', el.tagName.toLowerCase());
                window.parent.postMessage({ type: 'elementHover', selector: el.tagName }, '*');
              });
              window.addEventListener('mouseout', (e) => {
                e.target.classList.remove('lokalyze-hover');
              });
            </script>
          </head>
          <body style="transform: scale(${zoom})">${html}</body>
        </html>
      `;
