            <div className="mt-10 pt-10 border-t border-zinc-100 dark:border-zinc-800 flex justify-between">
              <span className="text-2xl font-black dark:text-white">{selectedLangs.length} <span className="text-[9px] uppercase tracking-widest text-zinc-400 block">Alvos</span></span>
              <span className="text-xl font-black text-violet-500">{MAX_CONCURRENT_JOBS}x <span className="text-[9px] uppercase tracking-widest text-zinc-400 block">Capacity</span></span>
            </div>
          </div>
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e2e2; border-radius: 10px; }
