  "Russian", "Arabic", "Hindi", "Turkish", "Dutch", "Polish", "Vietnamese",
  "Thai", "Indonesian", "Swedish", "Danish", "Finnish", "Norwegian",
  "Greek", "Czech", "Romanian", "Ukrainian", "Hebrew", "Malay"
];

const MAX_CONCURRENT_JOBS = 5;
const STORAGE_KEY_HTML = 'lokalyze_source_html';
const STORAGE_KEY_CSS = 'lokalyze_global_css';

interface TranslationJob {
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
  startTime?: number;
  estimatedSecondsLeft?: number;
  viewMode: 'code' | 'preview';
  tokenCount?: number;
}

interface ImageScanResult {
  url: string;
  detectedText: string;
  translatedText: string;
  status: 'idle' | 'scanning' | 'done' | 'error';
}

const App: React.FC = () => {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [sourceHtml, setSourceHtml] = useState<string>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_HTML);
    return saved || '<!-- Paste your HTML here -->\n<div class="hero" style="padding: 40px; text-align: center; font-family: sans-serif;">\n  <h1 style="color: #8b5cf6;">Global Expansion Starts Here</h1>\n  <p>LOKALYZE.SITE handles your complex DOM structures with precision.</p>\n</div>';
  });
  const [globalCss, setGlobalCss] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEY_CSS) || '/* Custom CSS */';
  });

  const [inputTab, setInputTab] = useState<'html' | 'css'>('html');
