  const [activeAssetTab, setActiveAssetTab] = useState<'translate' | 'assets'>('translate');
  const [imageAssets, setImageAssets] = useState<ImageScanResult[]>([]);

  const processingRefs = useRef<Set<string>>(new Set());

  useEffect(() => {
    document.documentElement.className = theme;
  }, [theme]);

  const triggerToast = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    triggerToast("Código copiado!");
  };

  const cleanStreamedHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();

  const executeTranslation = async (lang: string, source: string) => {
    if (processingRefs.current.has(lang)) return;
    processingRefs.current.add(lang);
    const startTime = Date.now();

    setJobs(prev => ({ 
      ...prev, 
      [lang]: { ...prev[lang], status: 'translating', startTime, progress: 1, viewMode: 'code' } 
    }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `STRICT TRANSLATION MODE: Localize HTML into ${lang}. Keep DOM structure exactly as is. Return ONLY HTML.\n\nSource:\n${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        fullText += c.text;
        const currentLength = fullText.length;
        const progress = Math.min(99, Math.round((currentLength / source.length) * 100));

        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress,
            tokenCount: Math.round(currentLength / 4)
          }
        }));
      }

      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'completed', progress: 100 } }));
    } catch (err: any) {
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'error', error: err.message } }));
    } finally {
      processingRefs.current.delete(lang);
