  const processingRefs = useRef<Set<string>>(new Set());

  useEffect(() => {
    document.documentElement.className = theme;
  }, [theme]);

  // Detector de Imagens no HTML original
  useEffect(() => {
    const imgRegex = /<img[^>]+src="([^">]+)"/g;
    const matches = Array.from(sourceHtml.matchAll(imgRegex));
    const urls = Array.from(new Set(matches.map(m => m[1])));

    setDetectedImages(prev => {
      const replacementsMap = new Map(prev.map(i => [i.originalUrl, i.replacementUrl]));
      return urls.map(url => ({
        originalUrl: url,
        replacementUrl: replacementsMap.get(url) || ''
      }));
    });
  }, [sourceHtml]);

  const triggerToast = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    triggerToast("Código copiado!");
  };

  const updateImageReplacement = (originalUrl: string, newUrl: string) => {
    setDetectedImages(prev => prev.map(img => 
      img.originalUrl === originalUrl ? { ...img, replacementUrl: newUrl } : img
    ));
  };

  const cleanStreamedHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();

