      [lang]: { ...prev[lang], status: 'translating', startTime, progress: 1, viewMode: 'code' } 
    }));

    // Criar instrução de substituição de imagem para o prompt
    const imageInstructions = detectedImages
      .filter(img => img.replacementUrl.trim() !== '')
      .map(img => `- Substitua o src de "${img.originalUrl}" por "${img.replacementUrl}"`)
      .join('\n');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `MODO TRADUÇÃO ESTRITA: Localize o HTML para ${lang}.
REGRAS:
1. Mantenha a estrutura DOM exatamente como está.
2. Traduza apenas textos visíveis e atributos alt/title.
${imageInstructions ? `3. SUBSTITUIÇÕES DE ASSETS:\n${imageInstructions}` : ''}
4. Retorne APENAS o código HTML limpo.

Fonte:
${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        fullText += c.text;
        const currentLength = fullText.length;
        const progress = Math.min(99, Math.round((currentLength / source.length) * 100));

        setJobs(prev => ({
          ...prev,
          [lang]: { 
            ...prev[lang], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress,
            tokenCount: Math.round(currentLength / 4)
          }
        }));
      }

      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'completed', progress: 100 } }));
    } catch (err: any) {
      setJobs(prev => ({ ...prev, [lang]: { ...prev[lang], status: 'error', error: err.message } }));
    } finally {
      processingRefs.current.delete(lang);
    }
  };

  useEffect(() => {
    const jobList = Object.values(jobs) as TranslationJob[];
    const active = jobList.filter(j => j.status === 'translating');
    const queued = jobList.filter(j => j.status === 'queued');

    if (active.length < MAX_CONCURRENT_JOBS && queued.length > 0) {
      executeTranslation(queued[0].lang, sourceHtml);
    }
    if (isBatchRunning && active.length === 0 && queued.length === 0 && jobList.length > 0) {
      setIsBatchRunning(false);
    }
  }, [jobs, isBatchRunning]);

  const startQueue = () => {
    setIsBatchRunning(true);
    const initialJobs: Record<string, TranslationJob> = {};
    selectedLangs.forEach(lang => {
      initialJobs[lang] = { lang, translatedHtml: '', status: 'queued', progress: 0, viewMode: 'code' };
    });
    setJobs(initialJobs);
  };

  const LivePreview = ({ html }: { html: string }) => {
    const srcDoc = useMemo(() => {
      return `<!DOCTYPE html><html><head><style>${globalCss} body{margin:0;padding:10px;background:white;color:#111;font-family:sans-serif;} img{max-width:100%;height:auto;}</style></head><body>${html || '...'}</body></html>`;
    }, [html, globalCss]);

    return (
      <iframe 
        srcDoc={srcDoc}
        className="w-full h-full border-0 bg-white" 
        sandbox="allow-scripts"
      />
    );
  };

  return (
    <div className="min-h-screen bg-[#fafafa] dark:bg-[#070707] text-[#111] dark:text-[#eee] font-sans selection:bg-violet-500/40 overflow-x-hidden">

      {showNotification && (
        <div className="fixed top-8 right-8 z-[200] animate-in slide-in-from-right fade-in">
          <div className="bg-black text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-violet-400 animate-pulse" />
            <span className="text-xs font-bold uppercase tracking-wider">{showNotification}</span>
          </div>
        </div>
      )}

      <nav className="max-w-[1800px] mx-auto px-8 py-8 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 rounded-xl bg-violet-600 flex items-center justify-center shadow-lg shadow-violet-500/30">
            <span className="text-white font-black text-xl italic">L</span>
          </div>
          <span className="text-xl font-black uppercase tracking-tighter dark:text-white">Mainframe<span className="text-violet-500">.Control</span></span>
        </div>
        <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="w-10 h-10 rounded-xl border border-zinc-200 dark:border-zinc-800 flex items-center justify-center">
          {theme === 'dark' ? '☼' : '☾'}
        </button>
      </nav>

      <main className="max-w-[1800px] mx-auto px-8 pb-20 grid grid-cols-1 xl:grid-cols-12 gap-10">

        <div className="xl:col-span-8 space-y-10">
          <section className="bg-white dark:bg-[#0e0e0e] rounded-[40px] p-8 border border-zinc-200 dark:border-white/5 shadow-xl">
            <div className="flex items-center justify-between mb-6">
              <div className="flex p-1 bg-zinc-100 dark:bg-zinc-900 rounded-xl">
                <button onClick={() => setInputTab('html')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest ${inputTab === 'html' ? 'bg-white dark:bg-zinc-800 text-violet-500' : 'text-zinc-500'}`}>Source Buffer</button>
                <button onClick={() => setInputTab('css')} className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest ${inputTab === 'css' ? 'bg-white dark:bg-zinc-800 text-violet-500' : 'text-zinc-500'}`}>CSS Global</button>
              </div>
              <button onClick={startQueue} disabled={isBatchRunning || selectedLangs.length === 0} className="bg-violet-600 text-white px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-violet-500/20 active:scale-95 transition-all disabled:opacity-20">Iniciar Deploy</button>
            </div>

            <textarea 
              value={inputTab === 'html' ? sourceHtml : globalCss}
              onChange={(e) => inputTab === 'html' ? setSourceHtml(e.target.value) : setGlobalCss(e.target.value)}
              className="w-full h-[300px] bg-zinc-50 dark:bg-black/40 border border-zinc-100 dark:border-white/5 rounded-3xl p-6 code-font text-sm outline-none focus:ring-1 ring-violet-500/20 resize-none"
            />
          </section>

          <section className="space-y-4">
            <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400 px-4">Mainframe Feed</h3>
            <div className="flex flex-col gap-2">
              {Object.values(jobs).map(job => (
                <div 
                  key={job.lang} 
                  onClick={() => setFocusedLang(focusedLang === job.lang ? null : job.lang)}
                  className={`group cursor-pointer p-5 bg-white dark:bg-[#0e0e0e] rounded-3xl border flex items-center gap-6 transition-all ${focusedLang === job.lang ? 'border-violet-500 ring-4 ring-violet-500/10' : 'border-zinc-100 dark:border-white/5'}`}
                >
                  <div className={`w-3 h-12 rounded-full ${job.status === 'completed' ? 'bg-emerald-500' : job.status === 'translating' ? 'bg-violet-500 animate-pulse' : 'bg-zinc-200 dark:bg-zinc-800'}`} />
                  <div className="flex-1">
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-sm font-black uppercase tracking-tight">{job.lang}</span>
                      <span className="text-[10px] font-mono text-zinc-400 uppercase tracking-widest">{job.status}</span>
                    </div>
                    <div className="h-1.5 w-full bg-zinc-100 dark:bg-zinc-800 rounded-full overflow-hidden">
                      <div className={`h-full transition-all duration-500 ${job.status === 'completed' ? 'bg-emerald-500' : 'bg-violet-600'}`} style={{ width: `${job.progress}%` }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        <div className="xl:col-span-4 space-y-10">
          {focusedLang && jobs[focusedLang] ? (
            <div className="bg-white dark:bg-[#0e0e0e] rounded-[44px] p-8 border border-violet-500 shadow-2xl animate-in slide-in-from-right">
              <div className="flex justify-between items-center mb-8">
                <h2 className="text-4xl font-black tracking-tighter">{focusedLang}</h2>
                <button onClick={() => setFocusedLang(null)} className="text-[10px] font-black uppercase text-zinc-400">Fechar</button>
              </div>
              <div className="h-[300px] rounded-3xl overflow-hidden bg-zinc-50 dark:bg-black/50 border border-zinc-100 dark:border-white/5 mb-6">
                {jobs[focusedLang].viewMode === 'preview' ? (
                  <LivePreview html={jobs[focusedLang].translatedHtml} />
                ) : (
                  <div className="p-6 h-full overflow-y-auto text-[11px] font-mono text-zinc-400 whitespace-pre-wrap break-all leading-relaxed custom-scrollbar">
                    {jobs[focusedLang].translatedHtml || '// Buffer vazio...'}
                  </div>
                )}
              </div>
              <div className="flex gap-2">
                <button onClick={() => setJobs(prev => ({...prev, [focusedLang]: {...prev[focusedLang], viewMode: prev[focusedLang].viewMode === 'code' ? 'preview' : 'code'}}))} className="flex-1 py-4 bg-zinc-100 dark:bg-zinc-900 rounded-2xl text-[10px] font-black uppercase tracking-widest">Vista: {jobs[focusedLang].viewMode}</button>
                {jobs[focusedLang].status === 'completed' && (
                  <button onClick={() => copyToClipboard(jobs[focusedLang].translatedHtml)} className="px-6 bg-emerald-500 text-white rounded-2xl flex items-center justify-center">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  </button>
                )}
              </div>
            </div>
          ) : (
            <div className="bg-white dark:bg-[#0e0e0e] rounded-[48px] p-8 border border-zinc-200 dark:border-white/5 shadow-xl">
               <div className="flex gap-2 p-1 bg-zinc-100 dark:bg-zinc-900 rounded-2xl mb-8">
                <button onClick={() => setActiveAssetTab('translate')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeAssetTab === 'translate' ? 'bg-white dark:bg-zinc-800 text-violet-500 shadow-sm' : 'text-zinc-500'}`}>Idiomas</button>
                <button onClick={() => setActiveAssetTab('assets')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeAssetTab === 'assets' ? 'bg-white dark:bg-zinc-800 text-violet-500 shadow-sm' : 'text-zinc-500'}`}>Assets</button>
               </div>

               {activeAssetTab === 'translate' ? (
                 <div className="space-y-6">
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Target Selector</h3>
                    <div className="grid grid-cols-2 gap-2 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                      {LANGUAGES.map(lang => (
                        <button 
                          key={lang} 
                          onClick={() => setSelectedLangs(prev => prev.includes(lang) ? prev.filter(l => l !== lang) : [...prev, lang])}
                          className={`px-4 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest border transition-all ${selectedLangs.includes(lang) ? 'bg-violet-600 border-violet-500 text-white' : 'bg-zinc-50 dark:bg-zinc-900 border-zinc-200 dark:border-zinc-800 text-zinc-500'}`}
                        >
                          {lang}
                        </button>
                      ))}
                    </div>
                 </div>
               ) : (
                 <div className="space-y-6">
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Image Asset Registry</h3>
                    <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                       {detectedImages.length === 0 ? (
                         <p className="text-[10px] text-center text-zinc-500 py-10">Nenhuma imagem detectada.</p>
                       ) : (
                         detectedImages.map((img, idx) => (
                           <div key={idx} className="p-4 bg-zinc-50 dark:bg-zinc-900/50 rounded-2xl border border-zinc-100 dark:border-white/5 space-y-3">
                              <div className="flex items-center gap-3">
                                 <img src={img.originalUrl} className="w-10 h-10 object-cover rounded-lg border border-white/10" alt="Preview" />
                                 <p className="text-[8px] font-mono text-zinc-500 truncate flex-1">{img.originalUrl}</p>
                              </div>
                              <input 
                                type="text"
                                placeholder="Nova URL de substituição..."
                                value={img.replacementUrl}
                                onChange={(e) => updateImageReplacement(img.originalUrl, e.target.value)}
                                className="w-full bg-white dark:bg-black px-3 py-2 rounded-xl text-[10px] outline-none border border-zinc-200 dark:border-zinc-800 focus:border-violet-500"
                              />
                           </div>
                         ))
                       )}
                    </div>
                 </div>
               )}
            </div>
          )}
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e2e2; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #222; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-in { animation: fadeUp 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
      `}</style>
    </div>
  );
};

const rootElement = document.getElementById('root');
if (rootElement) {
  createRoot(rootElement).render(<App />);
}

import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// --- CONFIGURATION & CONSTANTS ---
const LANGUAGES = [
  "English", "Spanish", "French", "German", "Chinese (Simplified)", 
  "Chinese (Traditional)", "Japanese", "Korean", "Portuguese", "Italian", 
  "Russian", "Arabic", "Hindi", "Turkish", "Dutch", "Polish", "Vietnamese",
  "Thai", "Indonesian", "Swedish", "Danish", "Finnish", "Norwegian",
  "Greek", "Czech", "Romanian", "Ukrainian", "Hebrew", "Malay"
];

const MAX_CONCURRENT_JOBS = 5;
const KEYS = {
  HTML: 'lokalyze_source_html',
  CSS: 'lokalyze_global_css',
  JOBS: 'lokalyze_jobs_history',
  ASSETS: 'lokalyze_asset_map'
};

// --- TYPES (DOMAIN ENTITIES) ---
interface TranslationJob {
  id: string;
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
  startTime: number;
  endTime?: number;
  tokenCount: number;
  viewMode: 'code' | 'preview';
}

interface ImageAsset {
  originalUrl: string;
  replacementUrl: string;
  id: string; // generated from url hash for stability
}

// --- ANALYTICS ADAPTER (PHASE B) ---
// This acts as a facade. Swap implementation details without breaking the app.
const Analytics = {
  track: (event: string, props: Record<string, any> = {}) => {
    // In a real scenario, this would call posthog.capture(event, props)
    // For now, we simulate a reliable logger
    if (process.env.NODE_ENV === 'development') {
      console.debug(`[Analytics] ${event}`, props);
    }
  },
  identify: (userId: string) => {
    // posthog.identify(userId)
  }
};

// --- UTILS ---
const generateId = () => Math.random().toString(36).substr(2, 9);
const cleanStreamedHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();

// --- APP COMPONENT ---
const App: React.FC = () => {
  // -- STATE: PERSISTENCE LAYER (PHASE A) --
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Source Code
  const [sourceHtml, setSourceHtml] = useState<string>(() => 
    localStorage.getItem(KEYS.HTML) || '<!-- Paste your HTML here -->\n<div class="hero" style="text-align: center;">\n  <h1>Global Expansion</h1>\n  <img src="https://via.placeholder.com/400" alt="Dashboard" />\n</div>'
  );

  const [globalCss, setGlobalCss] = useState<string>(() => 
    localStorage.getItem(KEYS.CSS) || 'body { font-family: sans-serif; }'
  );

  // Job Queue (The Mainframe State)
  const [jobs, setJobs] = useState<Record<string, TranslationJob>>({}); 

  // Asset Management (Phase C)
  const [detectedImages, setDetectedImages] = useState<ImageAsset[]>(() => {
    try {
      return JSON.parse(localStorage.getItem(KEYS.ASSETS) || '[]');
    } catch { return []; }
  });

  // UI State
  const [inputTab, setInputTab] = useState<'html' | 'css'>('html');
  const [activeTab, setActiveTab] = useState<'monitor' | 'assets'>('monitor');
  const [selectedLangs, setSelectedLangs] = useState<string[]>(['Spanish', 'German']);
  const [focusedJobId, setFocusedJobId] = useState<string | null>(null);
  const [isBatchRunning, setIsBatchRunning] = useState<boolean>(false);
  const [notification, setNotification] = useState<string | null>(null);

  // References for processing loop
  const processingRefs = useRef<Set<string>>(new Set());

  // -- EFFECTS: PERSISTENCE & INTEGRITY --
  useEffect(() => { document.documentElement.className = theme; }, [theme]);

  useEffect(() => localStorage.setItem(KEYS.HTML, sourceHtml), [sourceHtml]);
  useEffect(() => localStorage.setItem(KEYS.CSS, globalCss), [globalCss]);
  useEffect(() => localStorage.setItem(KEYS.ASSETS, JSON.stringify(detectedImages)), [detectedImages]);

  // Image Scanner Logic (Regex based for speed/integrity)
  useEffect(() => {
    const imgRegex = /<img[^>]+src=["']([^"']+)["']/g;
    const matches = Array.from(sourceHtml.matchAll(imgRegex));
    const currentUrls = Array.from(new Set(matches.map(m => m[1])));

    setDetectedImages(prev => {
      // Keep existing overrides if URL still exists
      const existingMap = new Map(prev.map(p => [p.originalUrl, p.replacementUrl]));

      return currentUrls.map(url => ({
        id: btoa(url).substring(0, 12), // Stable ID based on URL
        originalUrl: url,
        replacementUrl: existingMap.get(url) || ''
      }));
    });
  }, [sourceHtml]);

  // -- BUSINESS LOGIC: CORE ACTIONS --

  const triggerToast = (msg: string) => {
    setNotification(msg);
    setTimeout(() => setNotification(null), 3000);
  };

  const updateAsset = (id: string, newUrl: string) => {
    setDetectedImages(prev => prev.map(img => 
      img.id === id ? { ...img, replacementUrl: newUrl } : img
    ));
    Analytics.track('asset_updated', { assetId: id });
  };

  // The Engine
  const executeTranslation = async (jobId: string, lang: string, source: string) => {
    if (processingRefs.current.has(jobId)) return;
    processingRefs.current.add(jobId);

    const startTime = Date.now();
    setJobs(prev => ({ 
      ...prev, 
      [jobId]: { ...prev[jobId], status: 'translating', startTime, progress: 1 } 
    }));

    Analytics.track('job_started', { lang, jobId });

    // Prepare Prompt with Asset Overrides
    const assetInstructions = detectedImages
      .filter(img => img.replacementUrl.trim().length > 0)
      .map(img => `   - REPLACE SRC "${img.originalUrl}" WITH "${img.replacementUrl}"`)
      .join('\n');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview', // Speed optimized model
        contents: `SYSTEM: You are a strict HTML Localization Engine.
TASK: Translate the text content of the provided HTML into ${lang}.
RULES:
1. PRESERVE strict DOM structure. Do not add/remove tags.
2. PRESERVE classes, IDs, and style attributes.
3. TRANSLATE only human-readable text and 'alt'/'title' attributes.
4. ASSET OVERRIDES (Apply these strictly):
${assetInstructions}
5. OUTPUT: Return ONLY raw HTML code. No markdown fences.

INPUT HTML:
${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        fullText += c.text;
        const currentLength = fullText.length;
        // Estimation of progress based on source length (heuristic)
        const ratio = currentLength / source.length; 
        // Adjust heuristic: translated text is usually +/- 20% of source. 
        // We cap at 95% until done.
        const progress = Math.min(95, Math.round(ratio * 100)); 

        setJobs(prev => ({
          ...prev,
          [jobId]: { 
            ...prev[jobId], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress,
            tokenCount: Math.round(currentLength / 4)
          }
        }));
      }

      setJobs(prev => ({ ...prev, [jobId]: { ...prev[jobId], status: 'completed', progress: 100, endTime: Date.now() } }));
      Analytics.track('job_completed', { lang, jobId, duration: Date.now() - startTime });

    } catch (err: any) {
      console.error(err);
      setJobs(prev => ({ ...prev, [jobId]: { ...prev[jobId], status: 'error', error: err.message } }));
      Analytics.track('job_failed', { lang, jobId, error: err.message });
    } finally {
      processingRefs.current.delete(jobId);
    }
  };

  // Queue Manager (Polling Effect)
  useEffect(() => {
    const jobList = Object.values(jobs);
    const active = jobList.filter(j => j.status === 'translating');
    const queued = jobList.filter(j => j.status === 'queued');

    if (active.length < MAX_CONCURRENT_JOBS && queued.length > 0) {
      const nextJob = queued[0];
      executeTranslation(nextJob.id, nextJob.lang, sourceHtml);
    }

    if (isBatchRunning && active.length === 0 && queued.length === 0 && jobList.length > 0) {
      setIsBatchRunning(false);
      triggerToast("All jobs completed");
    }
  }, [jobs, isBatchRunning, sourceHtml]);

  const startBatch = () => {
    if (selectedLangs.length === 0) return triggerToast("Select at least one language");
    setIsBatchRunning(true);

    // Clear old jobs or keep history? For this request, we reset for the batch to show fresh progress
    const newJobs: Record<string, TranslationJob> = {};
    selectedLangs.forEach(lang => {
      const id = generateId();
      newJobs[id] = { 
        id, 
        lang, 
        translatedHtml: '', 
        status: 'queued', 
        progress: 0, 
        startTime: 0, 
        tokenCount: 0, 
        viewMode: 'preview' 
      };
    });
    setJobs(newJobs);
    Analytics.track('batch_started', { count: selectedLangs.length });
  };

  // -- UI COMPONENTS (Sub-components for performance/organization) --

  const LivePreview = useMemo(() => {
    return ({ html }: { html: string }) => {
      const srcDoc = `
        <!DOCTYPE html>
        <html>
          <head>
            <style>
              /* User Global CSS */
              ${globalCss}
              /* System Overrides for Preview Safety */
              body { margin: 0; padding: 16px; background: transparent; color: inherit; font-family: system-ui, sans-serif; }
              img { max-width: 100%; height: auto; display: block; }
            </style>
          </head>
          <body>${html || '<div style="opacity:0.5; text-align:center; padding-top:20px;">Buffer Empty</div>'}</body>
        </html>
      `;
      return (
        <iframe 
          srcDoc={srcDoc}
          className="w-full h-full border-0 bg-white dark:bg-zinc-900/50" 
          sandbox="allow-scripts"
          title="preview"
        />
      );
    };
  }, [globalCss]);

  // -- MAIN RENDER --
  return (
    <div className="min-h-screen bg-[#fafafa] dark:bg-[#050505] text-[#111] dark:text-[#eee] font-sans selection:bg-violet-500/30 overflow-x-hidden transition-colors duration-300">

      {/* Toast Notification */}
      {notification && (
        <div className="fixed top-6 right-6 z-50 animate-[slideIn_0.3s_ease-out] flex items-center gap-3 bg-[#111] text-white px-5 py-3 rounded-xl shadow-2xl shadow-black/20">
          <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse" />
          <span className="text-xs font-bold uppercase tracking-wider">{notification}</span>
        </div>
      )}

      {/* Navigation */}
      <nav className="border-b border-zinc-200 dark:border-white/5 bg-white/50 dark:bg-black/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-[1800px] mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-violet-600 to-indigo-600 flex items-center justify-center shadow-lg shadow-violet-500/20">
              <span className="text-white font-black italic text-sm">L</span>
            </div>
            <span className="text-sm font-black uppercase tracking-tighter dark:text-white">Mainframe<span className="text-violet-500">.OS</span></span>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-zinc-400">
              <span>Status:</span>
              <span className={`flex items-center gap-1 ${isBatchRunning ? 'text-emerald-500' : 'text-zinc-500'}`}>
                <span className={`w-1.5 h-1.5 rounded-full bg-current ${isBatchRunning ? 'animate-pulse' : ''}`} />
                {isBatchRunning ? 'Processing' : 'Idle'}
              </span>
            </div>
