      <main className="max-w-[1800px] mx-auto p-6 grid grid-cols-1 xl:grid-cols-12 gap-8">

        {/* COLUMN 1: INPUT BUFFER (Source of Truth) */}
        <div className="xl:col-span-4 flex flex-col gap-6 h-[calc(100vh-100px)]">
