                <button onClick={() => setInputTab('html')} className={`px-4 py-1.5 rounded-md text-[10px] font-bold uppercase tracking-widest transition-all ${inputTab === 'html' ? 'bg-white dark:bg-zinc-800 shadow-sm text-violet-600' : 'text-zinc-500 hover:text-zinc-400'}`}>HTML</button>
