          </section>
        </div>

        {/* COLUMN 2: MAINFRAME MONITOR & ASSETS (The visual core) */}
        <div className="xl:col-span-8 flex flex-col gap-6 h-[calc(100vh-100px)]">

          {/* Dashboard Header / Tabs */}
          <div className="flex items-center gap-4">
             <button onClick={() => setActiveTab('monitor')} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${activeTab === 'monitor' ? 'bg-white dark:bg-[#0e0e0e] border-zinc-200 dark:border-white/10 text-violet-500 shadow-xl' : 'border-transparent text-zinc-400 hover:text-zinc-600'}`}>
