                {/* LIST VIEW (Left side of dashboard) */}
                <div className={`${focusedJobId ? 'w-1/3 hidden md:flex' : 'w-full'} flex-col border-r border-zinc-100 dark:border-white/5 transition-all duration-500`}>
                   <div className="p-6 border-b border-zinc-100 dark:border-white/5 flex justify-between items-center bg-zinc-50/50 dark:bg-black/20">
