                          </div>
                          <div className="mt-2 flex justify-between items-center text-[9px] font-mono text-zinc-400 relative z-10">
                             <span>{job.tokenCount > 0 ? `${(job.tokenCount/1000).toFixed(1)}k tokens` : '-'}</span>
                             <span>{job.progress}%</span>
