                      ))}
                   </div>
                </div>

                {/* DRILL DOWN VIEW (Right side of dashboard) */}
                {focusedJobId && jobs[focusedJobId] ? (
                  <div className="flex-1 flex flex-col h-full bg-zinc-50 dark:bg-[#0a0a0a] animate-in slide-in-from-right duration-300">
                    <div className="p-6 border-b border-zinc-200 dark:border-white/5 flex justify-between items-center bg-white dark:bg-[#0e0e0e]">
                       <div>
                          <h2 className="text-2xl font-black tracking-tighter flex items-center gap-3">
                             {jobs[focusedJobId].lang} 
                             <span className={`px-2 py-0.5 rounded-md text-[9px] uppercase tracking-widest text-white ${jobs[focusedJobId].status === 'completed' ? 'bg-emerald-500' : 'bg-violet-500'}`}>{jobs[focusedJobId].status}</span>
                          </h2>
                       </div>
                       <div className="flex gap-2">
                          <button onClick={() => setJobs(prev => ({...prev, [focusedJobId]: {...prev[focusedJobId], viewMode: prev[focusedJobId].viewMode === 'preview' ? 'code' : 'preview'}}))} className="w-10 h-10 rounded-xl bg-zinc-100 dark:bg-zinc-800 flex items-center justify-center text-zinc-500 hover:text-black dark:hover:text-white transition-colors">
                            {jobs[focusedJobId].viewMode === 'preview' ? '</>' : '👁'}
                          </button>
                          <button onClick={() => setFocusedJobId(null)} className="w-10 h-10 rounded-xl border border-zinc-200 dark:border-white/10 flex items-center justify-center text-zinc-400 hover:bg-zinc-100 dark:hover:bg-zinc-800">✕</button>
                       </div>
                    </div>
                    <div className="flex-1 overflow-hidden relative">
                       {jobs[focusedJobId].viewMode === 'preview' ? (
                          <LivePreview html={jobs[focusedJobId].translatedHtml} />
                       ) : (
                          <textarea 
                            readOnly 
                            className="w-full h-full p-6 bg-transparent code-font text-xs text-zinc-600 dark:text-zinc-400 resize-none outline-none" 
                            value={jobs[focusedJobId].translatedHtml} 
                          />
                       )}
                    </div>
                  </div>
                ) : (
                  <div className="flex-1 hidden md:flex flex-col items-center justify-center text-zinc-300 dark:text-zinc-700">
                    <div className="w-24 h-24 rounded-3xl bg-zinc-100 dark:bg-white/5 flex items-center justify-center mb-6">
                       <span className="text-4xl">⌨</span>
                    </div>
                    <p className="text-xs font-bold uppercase tracking-widest">Select a job to inspect</p>
                  </div>
                )}
              </div>
            ) : (
              // ASSET MANAGER TAB
              <div className="h-full flex flex-col">
                 <div className="p-6 border-b border-zinc-100 dark:border-white/5 bg-zinc-50/50 dark:bg-black/20">
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Image Asset Registry</h3>
                    <p className="text-xs text-zinc-400 mt-1">Define overrides here. The engine will strictly replace these sources during translation generation.</p>
                 </div>
                 <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
                    {detectedImages.length === 0 ? (
                      <div className="p-12 text-center border-2 border-dashed border-zinc-200 dark:border-zinc-800 rounded-3xl">
                        <p className="text-xs font-bold text-zinc-400 uppercase">No &lt;img&gt; tags found in source HTML</p>
                      </div>
                    ) : (
                      detectedImages.map((img) => (
                        <div key={img.id} className="flex gap-6 p-6 bg-zinc-50 dark:bg-[#121212] rounded-3xl border border-zinc-100 dark:border-white/5 group hover:border-violet-500/30 transition-colors">
                           <div className="w-24 h-24 rounded-2xl bg-white dark:bg-black overflow-hidden border border-zinc-200 dark:border-white/10 shrink-0 relative">
                              <img src={img.originalUrl} alt="preview" className="w-full h-full object-cover" />
                              <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-[10px] text-white font-bold uppercase">Original</div>
                           </div>
                           <div className="flex-1 flex flex-col justify-center gap-3">
                              <div className="flex flex-col gap-1">
                                 <label className="text-[9px] font-black uppercase tracking-widest text-zinc-400">Original Source</label>
                                 <code className="text-[10px] bg-white dark:bg-black px-2 py-1 rounded border border-zinc-100 dark:border-white/10 text-zinc-500 truncate">{img.originalUrl}</code>
                              </div>
