```typescript
// Define a function to validate a URL
const isValidURL = (url: string): boolean => {
    try {
        new URL(url);
        return true;
    } catch (e) {
        return false;
    }
};

const downloadAllAssets = async () => {
  setIsDownloadingAssets(true);
  const zip = new JSZip();
  let successCount = 0;

  await Promise.all(detectedImages.map(async (img) => {
    if (!img.originalUrl) {
      console.warn("No originalUrl for image, skipping.");
      return;
    }

    // Validate the URL before attempting to fetch
    if (!isValidURL(img.originalUrl)) {
      console.warn(`Invalid URL, skipping: ${img.originalUrl}`);
      return;
    }

    try {
      const response = await fetch(img.originalUrl);
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const blob = await response.blob();
      zip.file(img.filename, blob);
      successCount++;
    } catch (e: any) {
      console.error(`Error to fetch ${img.originalUrl}`, e);
      // Removed the error toast so the user does not receive too many.
    }
  }));

  setIsDownloadingAssets(false);
  if (successCount === 0) {
      triggerToast("Could not download assets.");
      return;
  }
  const content = await zip.generateAsync({ type: "blob" });
  saveAs(content, "lokalyze-assets.zip");
  triggerToast(`Downloaded ${successCount} assets`);
};
```


