const KEYS = {
  HTML: 'lokalyze_source_html',
  CSS: 'lokalyze_global_css',
  JOBS: 'lokalyze_jobs_history',
  ASSETS: 'lokalyze_asset_map'
};

// --- TYPES (DOMAIN ENTITIES) ---
interface TranslationJob {
  id: string;
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
  startTime: number;
  endTime?: number;
  tokenCount: number;
  viewMode: 'code' | 'preview';
}

interface ImageAsset {
  originalUrl: string;
  replacementUrl: string;
  id: string; // generated from url hash for stability
}

// --- ANALYTICS ADAPTER (PHASE B) ---
const Analytics = {
  track: (event: string, props: Record<string, any> = {}) => {
    if (process.env.NODE_ENV === 'development') {
      console.debug(`[Analytics] ${event}`, props);
    }
  },
  identify: (userId: string) => {
    // posthog.identify(userId)
  }
};

// --- UTILS ---
const generateId = () => Math.random().toString(36).substr(2, 9);
const cleanStreamedHtml = (text: string) => text.replace(/```html\n?|```/g, '').trim();
const formatDuration = (ms: number) => {
  if (ms < 1000) return `${ms}ms`;
  return `${(ms / 1000).toFixed(1)}s`;
};

// --- ICONS (SVG) ---
const Icons = {
  Cpu: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
  Code: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>,
  Image: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>,
  Check: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>,
  Download: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>,
  Eye: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>,
  Close: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>,
  Copy: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>,
  Archive: () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>,
};

// --- APP COMPONENT ---
const App: React.FC = () => {
  // -- STATE: PERSISTENCE LAYER (PHASE A) --
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Source Code
  const [sourceHtml, setSourceHtml] = useState<string>(() => 
    localStorage.getItem(KEYS.HTML) || '<!-- Paste your HTML here -->\n<div class="hero" style="text-align: center;">\n  <h1>Global Expansion</h1>\n  <img src="https://via.placeholder.com/400" alt="Dashboard" />\n</div>'
  );

  const [globalCss, setGlobalCss] = useState<string>(() => 
    localStorage.getItem(KEYS.CSS) || 'body { font-family: sans-serif; }'
  );

  // Job Queue (The Mainframe State)
  const [jobs, setJobs] = useState<Record<string, TranslationJob>>({}); 

  // Asset Management (Phase C)
  const [detectedImages, setDetectedImages] = useState<ImageAsset[]>(() => {
    try {
      return JSON.parse(localStorage.getItem(KEYS.ASSETS) || '[]');
    } catch { return []; }
  });

  // UI State
  const [inputTab, setInputTab] = useState<'html' | 'css'>('html');
  const [activeTab, setActiveTab] = useState<'monitor' | 'assets'>('monitor');
  const [selectedLangs, setSelectedLangs] = useState<string[]>(['Spanish', 'German']);
  const [focusedJobId, setFocusedJobId] = useState<string | null>(null);
  const [isBatchRunning, setIsBatchRunning] = useState<boolean>(false);
  const [isDownloadingAssets, setIsDownloadingAssets] = useState<boolean>(false);
  const [notification, setNotification] = useState<string | null>(null);

  // References for processing loop
  const processingRefs = useRef<Set<string>>(new Set());

  // -- EFFECTS: PERSISTENCE & INTEGRITY --
  useEffect(() => { document.documentElement.className = theme; }, [theme]);

  useEffect(() => localStorage.setItem(KEYS.HTML, sourceHtml), [sourceHtml]);
  useEffect(() => localStorage.setItem(KEYS.CSS, globalCss), [globalCss]);
  useEffect(() => localStorage.setItem(KEYS.ASSETS, JSON.stringify(detectedImages)), [detectedImages]);

  // Image Scanner Logic (Regex based for speed/integrity)
  useEffect(() => {
    const imgRegex = /<img[^>]+src=["']([^"']+)["']/g;
    const matches = Array.from(sourceHtml.matchAll(imgRegex));
    const currentUrls = Array.from(new Set(matches.map(m => m[1])));

    setDetectedImages(prev => {
      // Keep existing overrides if URL still exists
      const existingMap = new Map(prev.map(p => [p.originalUrl, p.replacementUrl]));

      return currentUrls.map(url => ({
        id: btoa(url).substring(0, 12), // Stable ID based on URL
        originalUrl: url,
        replacementUrl: existingMap.get(url) || ''
      }));
    });
  }, [sourceHtml]);

  // -- BUSINESS LOGIC: CORE ACTIONS --

  const triggerToast = (msg: string) => {
    setNotification(msg);
    setTimeout(() => setNotification(null), 3000);
  };

  const updateAsset = (id: string, newUrl: string) => {
    setDetectedImages(prev => prev.map(img => 
      img.id === id ? { ...img, replacementUrl: newUrl } : img
    ));
    Analytics.track('asset_updated', { assetId: id });
  };

  const downloadHtml = (lang: string, html: string) => {
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `index-${lang.toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    triggerToast(`Downloaded ${lang} file`);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    triggerToast("Copied to clipboard");
  };

  // -- ASSET DOWNLOAD LOGIC --

  const downloadAsset = async (url: string, filename?: string) => {
    try {
      triggerToast("Downloading asset...");
      // Try to fetch to get a blob (cleaner download)
      const response = await fetch(url, { mode: 'cors' });
      if (!response.ok) throw new Error('Network block');
      const blob = await response.blob();
      const name = filename || url.split('/').pop()?.split('?')[0] || 'image.png';
      saveAs(blob, name);
      triggerToast("Download complete");
    } catch (e) {
      console.warn("Direct download failed, opening in new tab", e);
      // Fallback: Open in new tab
      window.open(url, '_blank');
      triggerToast("Opened in new tab (CORS restricted)");
    }
  };

  const downloadAllAssets = async () => {
    if (detectedImages.length === 0) return triggerToast("No assets to download");
    setIsDownloadingAssets(true);
    triggerToast("Packaging assets... this may take a moment");

    try {
        const zip = new JSZip();
        const folder = zip.folder("assets");
        let successCount = 0;

        // Parallel fetching
        await Promise.all(detectedImages.map(async (img) => {
            try {
                // Use original URL unless a replacement is provided? 
                // Usually user wants to download what's in the source. 
                // If replacement exists, they probably already have it. 
                // Let's stick to originalUrl from the source.
                const response = await fetch(img.originalUrl, { mode: 'cors' });
                if (response.ok) {
                    const blob = await response.blob();
                    // Generate a clean filename
                    let filename = img.originalUrl.split('/').pop()?.split('?')[0];
                    if (!filename || filename.length > 50 || !filename.includes('.')) {
                        filename = `image-${img.id}.png`; // Fallback
                    }
                    folder?.file(filename, blob);
                    successCount++;
                }
            } catch (e) {
                console.warn(`Failed to fetch ${img.originalUrl}`, e);
            }
        }));

        if (successCount === 0) {
            throw new Error("No assets could be accessed (CORS blocked)");
        }

        const content = await zip.generateAsync({ type: "blob" });
        saveAs(content, "lokalyze-assets.zip");
        triggerToast(`Downloaded ${successCount} assets`);

    } catch (e: any) {
        console.error(e);
        triggerToast(e.message || "Batch download failed");
    } finally {
        setIsDownloadingAssets(false);
    }
  };

  // The Engine
  const executeTranslation = async (jobId: string, lang: string, source: string) => {
    if (processingRefs.current.has(jobId)) return;
    processingRefs.current.add(jobId);

    const startTime = Date.now();
    setJobs(prev => ({ 
      ...prev, 
      [jobId]: { ...prev[jobId], status: 'translating', startTime, progress: 1 } 
    }));

    Analytics.track('job_started', { lang, jobId });

    // Prepare Prompt with Asset Overrides
    const assetInstructions = detectedImages
      .filter(img => img.replacementUrl.trim().length > 0)
      .map(img => `   - REPLACE SRC "${img.originalUrl}" WITH "${img.replacementUrl}"`)
      .join('\n');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const stream = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: `SYSTEM: You are a strict HTML Localization Engine and Elite Copywriter.
TASK: Translate the text content of the provided HTML into ${lang}.

LOCALIZATION & COPYWRITING INSTRUCTIONS:
- Native Adaptation: The translation must sound 100% natural to a native speaker. Avoid "translationese".
- Cultural Localization: Adapt examples (names, locations, currencies, cultural references) to be familiar to the target audience to ensure immediate understanding.
- Persuasion Preservation: CRITICAL. Do NOT alter the psychological triggers, persuasive structure, or the intent of calls-to-action (CTAs). The emotional impact must remain identical to the original.
- Structural Integrity: Keep the exact flow of the copy.

TECHNICAL RULES (NON-NEGOTIABLE):
1. PRESERVE strict DOM structure. Do not add, remove, or reorder tags.
2. PRESERVE all classes, IDs, data-attributes, and inline styles exactly.
3. TRANSLATE only human-readable text nodes and 'alt'/'title'/'placeholder' attributes.
4. ASSET OVERRIDES (Apply these strictly):
${assetInstructions}
5. OUTPUT: Return ONLY valid raw HTML code. No markdown, no explanations.

INPUT HTML:
${source}`,
      });

      let fullText = '';
      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        fullText += c.text;
        const currentLength = fullText.length;
        const ratio = currentLength / source.length; 
        const progress = Math.min(95, Math.round(ratio * 100)); 

        setJobs(prev => ({
          ...prev,
          [jobId]: { 
            ...prev[jobId], 
            translatedHtml: cleanStreamedHtml(fullText),
            progress,
            tokenCount: Math.round(currentLength / 4)
          }
        }));
      }

      setJobs(prev => ({ ...prev, [jobId]: { ...prev[jobId], status: 'completed', progress: 100, endTime: Date.now() } }));
      Analytics.track('job_completed', { lang, jobId, duration: Date.now() - startTime });

    } catch (err: any) {
      console.error(err);
      setJobs(prev => ({ ...prev, [jobId]: { ...prev[jobId], status: 'error', error: err.message } }));
      Analytics.track('job_failed', { lang, jobId, error: err.message });
    } finally {
      processingRefs.current.delete(jobId);
    }
  };

  // Queue Manager (Polling Effect)
  useEffect(() => {
    const jobList = Object.values(jobs) as TranslationJob[];
    const active = jobList.filter(j => j.status === 'translating');
    const queued = jobList.filter(j => j.status === 'queued');

    if (active.length < MAX_CONCURRENT_JOBS && queued.length > 0) {
      const nextJob = queued[0];
      executeTranslation(nextJob.id, nextJob.lang, sourceHtml);
    }

    if (isBatchRunning && active.length === 0 && queued.length === 0 && jobList.length > 0) {
      setIsBatchRunning(false);
      triggerToast("All jobs completed");
    }
  }, [jobs, isBatchRunning, sourceHtml]);

  const startBatch = () => {
    if (selectedLangs.length === 0) return triggerToast("Select at least one language");

    // Safety check for empty source
    if (!sourceHtml.trim() || sourceHtml.length < 10) return triggerToast("Source HTML looks empty");

    setIsBatchRunning(true);
    setActiveTab('monitor'); // Auto switch to monitor

    const newJobs: Record<string, TranslationJob> = {};
    selectedLangs.forEach(lang => {
      const id = generateId();
      newJobs[id] = { 
        id, 
        lang, 
        translatedHtml: '', 
        status: 'queued', 
        progress: 0, 
        startTime: 0, 
        tokenCount: 0, 
        viewMode: 'preview' 
      };
    });
    setJobs(newJobs);
    Analytics.track('batch_started', { count: selectedLangs.length });
  };

  // -- UI COMPONENTS (Sub-components for performance/organization) --

  const LivePreview = useMemo(() => {
    return ({ html }: { html: string }) => {
      const srcDoc = `
        <!DOCTYPE html>
        <html>
          <head>
            <style>
              ${globalCss}
              body { margin: 0; padding: 16px; background: transparent; color: inherit; font-family: system-ui, sans-serif; }
              img { max-width: 100%; height: auto; display: block; }
            </style>
          </head>
          <body>${html || '<div style="opacity:0.5; text-align:center; padding-top:20px;">Buffer Empty</div>'}</body>
        </html>
      `;
      return (
        <iframe 
          srcDoc={srcDoc}
          className="w-full h-full border-0 bg-white dark:bg-zinc-900/50" 
          sandbox="allow-scripts"
          title="preview"
        />
      );
    };
  }, [globalCss]);

  // -- MAIN RENDER --
  return (
    <div className="min-h-screen bg-zinc-50 dark:bg-[#050505] text-zinc-900 dark:text-[#eee] font-sans selection:bg-violet-500/30 overflow-x-hidden transition-colors duration-300">

      {/* Toast Notification */}
      {notification && (
        <div className="fixed top-6 right-6 z-50 animate-[slideIn_0.3s_ease-out] flex items-center gap-3 bg-zinc-900 text-white px-5 py-3 rounded-xl shadow-2xl shadow-black/20 border border-white/10">
          <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse" />
          <span className="text-xs font-bold uppercase tracking-wider">{notification}</span>
        </div>
      )}

      {/* Navigation */}
      <nav className="border-b border-zinc-200 dark:border-white/5 bg-white/50 dark:bg-black/50 backdrop-blur-xl sticky top-0 z-40">
        <div className="max-w-[1800px] mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-violet-600 to-indigo-600 flex items-center justify-center shadow-lg shadow-violet-500/20">
              <span className="text-white font-black italic text-sm">L</span>
            </div>
            <span className="text-sm font-black uppercase tracking-tighter dark:text-white">Mainframe<span className="text-violet-500">.OS</span></span>
            <div className="h-4 w-px bg-zinc-300 dark:bg-white/10 mx-2 hidden md:block"></div>
            <span className="hidden md:inline-block text-[10px] font-bold uppercase tracking-widest text-zinc-400">Workspace / Local</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-zinc-400 bg-zinc-100 dark:bg-white/5 px-3 py-1.5 rounded-full">
              <span>Status:</span>
              <span className={`flex items-center gap-1.5 ${isBatchRunning ? 'text-emerald-500' : 'text-zinc-500'}`}>
                <span className={`w-1.5 h-1.5 rounded-full bg-current ${isBatchRunning ? 'animate-pulse' : ''}`} />
                {isBatchRunning ? 'Processing' : 'Ready'}
              </span>
            </div>
            <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="w-8 h-8 rounded-lg border border-zinc-200 dark:border-zinc-800 flex items-center justify-center hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors">
              {theme === 'dark' ? '☼' : '☾'}
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-[1800px] mx-auto p-4 md:p-6 grid grid-cols-1 xl:grid-cols-12 gap-6 h-[calc(100vh-64px)]">

        {/* COLUMN 1: INPUT BUFFER (Source of Truth) */}
        <div className="xl:col-span-4 flex flex-col gap-6 h-full overflow-hidden">

          {/* EDITOR PANEL */}
          <section className="flex-1 bg-white dark:bg-[#0e0e0e] rounded-[24px] border border-zinc-200 dark:border-white/5 shadow-xl flex flex-col overflow-hidden relative group">
            <div className="p-3 border-b border-zinc-100 dark:border-white/5 flex items-center justify-between bg-zinc-50/50 dark:bg-zinc-900/20 backdrop-blur-sm">
              <div className="flex bg-zinc-200/50 dark:bg-black/50 p-1 rounded-lg">
                <button onClick={() => setInputTab('html')} className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-[10px] font-bold uppercase tracking-widest transition-all ${inputTab === 'html' ? 'bg-white dark:bg-zinc-800 shadow-sm text-violet-600' : 'text-zinc-500 hover:text-zinc-400'}`}>
                   <Icons.Code /> HTML
                </button>
                <button onClick={() => setInputTab('css')} className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-[10px] font-bold uppercase tracking-widest transition-all ${inputTab === 'css' ? 'bg-white dark:bg-zinc-800 shadow-sm text-violet-600' : 'text-zinc-500 hover:text-zinc-400'}`}>
                   <Icons.Code /> CSS
                </button>
              </div>
              <div className="text-[9px] font-mono text-zinc-400 bg-zinc-100 dark:bg-white/5 px-2 py-1 rounded">
                {inputTab === 'html' ? `${sourceHtml.length}` : `${globalCss.length}`} chars
              </div>
            </div>
            <textarea 
              value={inputTab === 'html' ? sourceHtml : globalCss}
              onChange={(e) => inputTab === 'html' ? setSourceHtml(e.target.value) : setGlobalCss(e.target.value)}
              className="flex-1 w-full bg-transparent p-6 code-font text-xs leading-relaxed resize-none outline-none text-zinc-700 dark:text-zinc-400 focus:bg-zinc-50/50 dark:focus:bg-white/5 transition-colors"
              spellCheck={false}
              placeholder={`// Paste your ${inputTab.toUpperCase()} code here...`}
            />
          </section>

          {/* CONTROL PANEL (Fixed Height, Scrollable Content, Sticky Footer) */}
          <section className="h-[40%] min-h-[300px] bg-white dark:bg-[#0e0e0e] rounded-[24px] border border-zinc-200 dark:border-white/5 shadow-xl flex flex-col overflow-hidden relative group">

             {/* Header */}
             <div className="p-4 border-b border-zinc-100 dark:border-white/5 flex items-center justify-between shrink-0 bg-white dark:bg-[#0e0e0e] z-10">
                <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Target Selector</span>
                <span className="text-[9px] font-bold text-violet-500 bg-violet-500/10 px-2 py-0.5 rounded-full">{selectedLangs.length} Selected</span>
             </div>

             {/* Scrollable Language List */}
             <div className="flex-1 overflow-y-auto custom-scrollbar p-4">
                <div className="grid grid-cols-2 gap-2">
                  {LANGUAGES.map(lang => (
                    <button 
                      key={lang}
                      onClick={() => setSelectedLangs(prev => prev.includes(lang) ? prev.filter(l => l !== lang) : [...prev, lang])}
                      className={`px-3 py-2.5 rounded-xl text-[10px] font-bold uppercase tracking-wider text-left border transition-all ${selectedLangs.includes(lang) ? 'bg-violet-600 border-violet-500 text-white shadow-lg shadow-violet-500/20' : 'bg-zinc-50 dark:bg-zinc-900/50 border-zinc-200 dark:border-zinc-800 text-zinc-500 hover:border-zinc-300 dark:hover:border-zinc-700'}`}
                    >
                      <div className="flex items-center justify-between w-full">
                        <span>{lang}</span>
                        {selectedLangs.includes(lang) && <Icons.Check />}
                      </div>
                    </button>
                  ))}
                </div>
             </div>

             {/* Sticky Footer CTA */}
             <div className="p-4 bg-white/80 dark:bg-[#0e0e0e]/80 backdrop-blur-md border-t border-zinc-100 dark:border-white/5 shrink-0 z-10">
                <div className="flex items-center justify-between mb-3 px-1">
                   <div className="flex items-center gap-2 text-[9px] font-bold uppercase tracking-widest text-zinc-500">
                      <Icons.Image />
                      <span>Assets Detected: {detectedImages.length}</span>
                   </div>
                   {detectedImages.filter(i => i.replacementUrl).length > 0 && (
                      <span className="text-[9px] font-bold text-emerald-500 bg-emerald-500/10 px-2 py-0.5 rounded-full">
                         {detectedImages.filter(i => i.replacementUrl).length} Overrides
                      </span>
                   )}
                </div>
                <button 
                  onClick={startBatch}
                  disabled={isBatchRunning}
                  className="w-full py-4 bg-zinc-900 dark:bg-white text-white dark:text-black rounded-xl text-[10px] font-black uppercase tracking-[0.2em] hover:scale-[1.01] active:scale-[0.99] transition-all disabled:opacity-50 disabled:scale-100 shadow-xl flex items-center justify-center gap-3"
                >
                  {isBatchRunning ? <span className="animate-spin">⏳</span> : <Icons.Cpu />}
                  {isBatchRunning ? 'Processing Batch...' : 'Initialize Batch'}
                </button>
             </div>
          </section>
        </div>

        {/* COLUMN 2: MAINFRAME MONITOR & ASSETS (The visual core) */}
        <div className="xl:col-span-8 flex flex-col gap-6 h-full overflow-hidden">

          {/* Dashboard Header / Tabs */}
          <div className="flex items-center gap-2 shrink-0">
             <button onClick={() => setActiveTab('monitor')} className={`px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all flex items-center gap-2 ${activeTab === 'monitor' ? 'bg-white dark:bg-[#0e0e0e] border-zinc-200 dark:border-white/10 text-violet-500 shadow-xl' : 'border-transparent text-zinc-400 hover:text-zinc-600 hover:bg-white/50 dark:hover:bg-white/5'}`}>
                <Icons.Cpu /> Live Monitor
             </button>
