                                      className="w-full bg-zinc-50 dark:bg-black pl-3 pr-10 py-2.5 rounded-xl text-[11px] border border-zinc-200 dark:border-zinc-800 focus:border-violet-500 outline-none transition-all shadow-sm focus:shadow-violet-500/10 font-mono"
                                    />
                                    {img.replacementUrl && (
                                      <div className="absolute right-3 top-1/2 -translate-y-1/2 text-emerald-500">
                                        <Icons.Check />
                                      </div>
                                    )}
                                 </div>
                              </div>
                           </div>
                        </div>
                      ))
                    )}
                 </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #d4d4d8; border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: #333; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes slideIn { from { transform: translateY(-10px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
      `}</style>
    </div>
  );
};

