// --- TYPES (DOMAIN ENTITIES) ---
interface TranslationJob {
  id: string;
  lang: string;
  translatedHtml: string;
  status: 'queued' | 'translating' | 'completed' | 'error';
  progress: number;
  error?: string;
  startTime: number;
  endTime?: number;
  tokenCount: number;
  viewMode: 'code' | 'preview';
}

interface ImageAsset {
  originalUrl: string;
  replacementUrl: string;
  id: string; // generated from url hash for stability
}

// New Entity for History
interface Project {
  id: string;
  name: string;
  createdAt: number;
  lastModified: number;
  sourceHtml: string;
  globalCss: string;
  detectedImages: ImageAsset[];
  jobs: Record<string, TranslationJob>;
  selectedLangs: string[];
}

