    const finalTaskName = taskName.trim() || `Batch #${Date.now().toString().slice(-6)}`;

    const newJobs: Record<string, TranslationJob> = {};
    selectedLangs.forEach(lang => {
      const id = generateId();
      newJobs[id] = { 
        id, 
        lang, 
        translatedHtml: '', 
        status: 'queued', 
        progress: 0, 
        startTime: 0, 
        tokenCount: 0, 
        viewMode: 'preview' 
      };
    });

    const newProject: Project = {
      id: newProjectId,
      name: finalTaskName,
      createdAt: Date.now(),
      lastModified: Date.now(),
      sourceHtml,
      globalCss,
      detectedImages,
      detectedIframes,
      jobs: newJobs,
      selectedLangs
    };

    setHistory(prev => [newProject, ...prev]);
    setActiveProjectId(newProjectId);
    setJobs(newJobs);

    // Explicit save of new project
    dbHelper.save(newProject);
    Analytics.track('batch_started', { count: selectedLangs.length, projectId: newProjectId });
