function extractIframes(html: string): RegExpMatchArray[] {
    const iframeRegex = /<iframe[^>]+src="([^"]+)"[^>]*><\/iframe>/gi;
    let match;
    const matches: RegExpMatchArray[] = [];
    while ((match = iframeRegex.exec(html)) !== null) {
        matches.push(match);
    }
    return matches;
}

const App = () => {
    const [sourceHtml, setSourceHtml] = useState('');
    const [debouncedSourceHtml, setDebouncedSourceHtml] = useState('');
    const [detectedIframes, setDetectedIframes] = useState<
        {
            id: string;
            originalUrl: string;
            replacementUrl: string;
            htmlContent: string;
