// Safe Asset ID Generation (Handles Unicode URLs)
const safeAssetId = (url: string) => {
  try {
    return btoa(url).substring(0, 12);
  } catch (e) {
    return btoa(encodeURIComponent(url)).substring(0, 12);
  }
};

// Helper to fetch image and convert to base64
const urlToBase64 = async (url: string): Promise<{ data: string, mimeType: string }> => {
  const response = await fetch(url, { mode: 'cors' }); 
  if (!response.ok) throw new Error(`Failed to fetch image: ${response.statusText}`);
  const blob = await response.blob();
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({ data: base64Data, mimeType: blob.type });
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

// --- HOOKS ---
function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);
    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);
  return debouncedValue;
}

